(window.courseContentFiles = window.courseContentFiles || {})["000003/0012"] = "<!DOCTYPE html>\n<html lang=\"bg\">\n<head>\n  <meta charset=\"UTF-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>1</title>\n  <link rel=\"stylesheet\" href=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.css\">\n  <style>\n    body { \n      font-family: \"Open Sans\", Arial, sans-serif; \n      max-width: 1550px; \n      margin: 0.5rem auto; \n      padding: 0 1rem; \n      line-height: 1.6; \n      color: #1f2937; \n    }\n    h1, h2, h3, h4 { \n      font-weight: 600; \n      margin-top: 0.7em;\n      margin-bottom: 0;\n      color: #588157;\n    }\n    h1 { font-size: 1.65em; }\n    h2 { font-size: 1.3em; }\n    h3 { font-size: 1.1em; margin-bottom: 0; }\n    h4 { font-size: 1.05em; margin-bottom: 0; }\n    h1 + h2, h1 + h3, h1 + h4, h2 + h3, h2 + h4, h3 + h4 { margin-top: 0.1em; }\n    p { \n      margin: 0.3em 0; \n      white-space: pre-wrap;\n    }\n    hr {\n      margin: 0.45em 0 0.2em;\n    }\n    hr + h1,\n    hr + h2,\n    hr + h3,\n    hr + h4 {\n      margin-top: 0.2em;\n    }\n    hr + p,\n    hr + ul,\n    hr + ol,\n    hr + blockquote,\n    hr + pre,\n    hr + table {\n      margin-top: 0.08em;\n    }\n    p + ul, p + ol { margin-top: 0.2em; }\n    h1 + p, h2 + p, h3 + p, h4 + p,\n    h1 + ul, h2 + ul, h3 + ul, h4 + ul,\n    h1 + ol, h2 + ol, h3 + ol, h4 + ol { \n      margin-top: 0; \n    }\n    ul, ol { \n      margin: 0.2em 0; \n      padding-left: 1.5em; \n      list-style-position: outside;\n    }\n    li { margin: 0.2em 0; }\n    li p {\n      margin: 0;\n      padding: 0;\n      display: inline;\n    }\n    li > ul, li > ol {\n      margin: 0.15em 0 0 0;\n      padding-left: 1.5em;\n    }\n    ul ul, ul ol, ol ul, ol ol {\n      margin-top: 0.1em;\n      padding-left: 1.5em;\n    }\n    ul ul { list-style-type: circle; }\n    ul ul ul { list-style-type: square; }\n    strong { font-weight: 600; }\n    em { font-style: italic; }\n    code { \n      background: rgba(218, 215, 205, 0.3); \n      padding: 2px 6px; \n      border-radius: 3px; \n      font-family: \"Courier New\", monospace; \n      font-size: 0.9em; \n    }\n    pre {\n      background: rgba(255, 255, 255, 0.5);\n      padding: 12px;\n      border-radius: 4px;\n      overflow-x: auto;\n      margin: 0.5em 0;\n      font-family: \"Courier New\", monospace;\n    }\n    pre code {\n      background: none;\n      padding: 0;\n    }\n    blockquote {\n      border-left: 3px solid #588157;\n      padding-left: 1em;\n      margin: 0.5em 0;\n      font-style: italic;\n      color: #166534;\n    }\n    table { \n      border-collapse: collapse; \n      margin: 0.75em 0; \n      width: 100%; \n      table-layout: auto;\n    }\n    th, td { \n      border: 1px solid rgba(2, 2, 2, 0.2);\n      padding: 6px 10px; \n      text-align: left; \n      vertical-align: top;\n      height: 24px;\n      line-height: 1.2;\n    }\n    thead th { \n      background: rgba(88, 129, 87, 0.13); \n      font-weight: 600; \n    }\n    tbody tr:nth-child(odd) { \n      background: rgba(88, 129, 87, 0.06); \n    }\n    /* Image alignment rules for exported content and md-viewer */\n    img[data-align=\"left\"] {\n      display: block;\n      margin: 8px auto 8px 0;\n    }\n    img[data-align=\"center\"] {\n      display: block;\n      margin: 8px auto;\n    }\n    img[data-align=\"right\"] {\n      display: block;\n      margin: 8px 0 8px auto;\n    }\n    .audio-link-inline {\n      display: inline-flex;\n      align-items: center;\n      gap: 8px;\n      margin: 0.2em 0;\n      max-width: 100%;\n      vertical-align: middle;\n    }\n    .audio-link-icon {\n      width: 28px;\n      height: 28px;\n      border: 1px solid #588157;\n      border-radius: 999px;\n      background: #f0f7f0;\n      color: #2f5d50;\n      cursor: pointer;\n      font-size: 14px;\n      line-height: 1;\n      display: inline-flex;\n      align-items: center;\n      justify-content: center;\n      flex: 0 0 auto;\n    }\n    .audio-link-inline audio {\n      position: absolute;\n      width: 1px;\n      height: 1px;\n      opacity: 0;\n      overflow: hidden;\n      pointer-events: none;\n    }\n    .audio-link-icon img {\n      width: 14px;\n      height: 14px;\n      object-fit: contain;\n      pointer-events: none;\n    }\n    a {\n      color: inherit; /* Changed to inherit */\n      text-decoration: underline;\n    }\n    a:hover {\n      color: #74b673;\n    }\n    /* Keep <p> tags inside list items on same line (as they appear in editor) */\n    li p {\n      margin: 0 !important;\n      padding: 0 !important;\n      display: inline !important;\n    }\n    /* Prevent nested list paragraph issues */\n    li > ul,\n    li > ol {\n      margin: 0.15em 0 0 0;\n      padding-left: 1.5em;\n    }\n    /* Ensure list structure is clean */\n    ul ul, ul ol,\n    ol ul, ol ol {\n      margin-top: 0.1em;\n      padding-left: 1.5em;\n    }\n    @media (max-width: 768px) {\n      body {\n        margin: 0.5rem 0;\n        padding: 0 0.5rem;\n        font-size: 16px;\n      }\n      h1 { font-size: 1.65em; }\n      h2 { font-size: 1.3em; }\n      h3 { font-size: 1.1em; }\n      p { margin: 0.3em 0; }\n      ul, ol { padding-left: 1.5em; }\n      li { margin: 0.2em 0; }\n      table { font-size: 0.9em; }\n      th, td { padding: 6px 10px; }\n    }\n    .editor-note {\n      text-decoration: underline dotted #a3b18a;\n      text-decoration-thickness: 2px;\n      text-underline-offset: 2px;\n      text-decoration-skip-ink: none;\n      cursor: help;\n      position: relative;\n    }\n    .note-tooltip {\n      display: none;\n      position: absolute;\n      background-color: #f0f7f0;\n      color: #1f2937;\n      border: 1px solid #588157;\n      border-radius: 4px;\n      padding: 8px 12px;\n      width: fit-content;\n      max-width: min(700px, calc(100vw - 20px));\n      max-height: calc(100vh - 20px);\n      overflow: auto;\n      box-sizing: border-box;\n      box-shadow: 0 2px 8px rgba(0,0,0,0.2);\n      z-index: 10000;\n      font-size: 0.9em;\n      line-height: 1.4;\n      word-wrap: break-word;\n    }\n    .note-tooltip ul, .note-tooltip ol {\n      margin: 0 !important;\n      padding-left: 20px !important;\n    }\n    .note-tooltip li {\n      margin: 0 0 0.1em 0 !important;\n      padding: 0 !important;\n      line-height: 1.2 !important;\n    }\n    .note-tooltip li:last-child {\n      margin-bottom: 0 !important;\n    }\n    .note-tooltip .note-table-scroll {\n      overflow-x: hidden;\n      margin: 0.3em 0;\n      max-width: 100%;\n    }\n    .note-tooltip table {\n      border-collapse: collapse;\n      width: 100%;\n      max-width: 100%;\n      min-width: 0;\n      table-layout: fixed;\n      background: #ffffff;\n    }\n    .note-tooltip th,\n    .note-tooltip td {\n      border: 1px solid rgba(88, 129, 87, 0.35);\n      padding: 4px 8px;\n      text-align: left;\n      vertical-align: top;\n      line-height: 1.3;\n      white-space: normal;\n      overflow-wrap: anywhere;\n      word-break: break-word;\n    }\n    .note-tooltip thead th {\n      background: rgba(88, 129, 87, 0.12);\n      font-weight: 600;\n    }\n  </style>\n  <script>\n    document.addEventListener('DOMContentLoaded', function() {\n      const tooltip = document.createElement('div');\n      tooltip.className = 'note-tooltip';\n      document.body.appendChild(tooltip);\n\n      function parseNoteMarkdown(text) {\n        if (!text) return '';\n        \n        const splitTableCells = function(line) {\n          return String(line || '')\n            .trim()\n            .replace(/^\\|/, '')\n            .replace(/\\|$/, '')\n            .split('|')\n            .map(function(cell) { return cell.trim(); });\n        };\n\n        const isTableSeparatorLine = function(line) {\n          const cells = splitTableCells(line);\n          return cells.length > 0 && cells.every(function(cell) {\n            return /^:?-{3,}:?$/.test(cell);\n          });\n        };\n\n        const getTableAlignment = function(cell) {\n          if (/^:-{3,}:$/.test(cell)) return 'center';\n          if (/^-{3,}:$/.test(cell)) return 'right';\n          if (/^:-{3,}$/.test(cell)) return 'left';\n          return '';\n        };\n\n        let lines = text.split('\\n');\n        let html = [];\n        let stack = [];\n        \n        for (let i = 0; i < lines.length; i++) {\n          let line = lines[i];\n          \n          let indentMatch = line.match(/^(\\s*)/);\n          let indent = indentMatch ? indentMatch[1].length : 0;\n          let content = line.trim();\n\n          const nextLine = i + 1 < lines.length ? lines[i + 1].trim() : '';\n          const maybeTableHeader = content.includes('|') && splitTableCells(content).length >= 2;\n          const maybeTableSeparator = nextLine.includes('|') && isTableSeparatorLine(nextLine);\n\n          if (maybeTableHeader && maybeTableSeparator) {\n            while (stack.length > 0) {\n              let closed = stack.pop();\n              html.push('</' + closed.type + '>');\n            }\n\n            const headerCells = splitTableCells(content);\n            const alignCells = splitTableCells(nextLine);\n\n            html.push('<div class=\"note-table-scroll\"><table><thead><tr>');\n            headerCells.forEach(function(cell, idx) {\n              const align = getTableAlignment(alignCells[idx] || '');\n              const alignAttr = align ? ' style=\"text-align:' + align + ';\"' : '';\n              html.push('<th' + alignAttr + '>' + cell + '</th>');\n            });\n            html.push('</tr></thead><tbody>');\n\n            i += 2;\n            while (i < lines.length) {\n              const rowLine = lines[i].trim();\n              if (!rowLine || !rowLine.includes('|')) break;\n              if (isTableSeparatorLine(rowLine)) {\n                i++;\n                continue;\n              }\n\n              const rowCells = splitTableCells(rowLine);\n              if (rowCells.length === 0) {\n                i++;\n                continue;\n              }\n\n              html.push('<tr>');\n              rowCells.forEach(function(cell, idx) {\n                const align = getTableAlignment(alignCells[idx] || '');\n                const alignAttr = align ? ' style=\"text-align:' + align + ';\"' : '';\n                html.push('<td' + alignAttr + '>' + cell + '</td>');\n              });\n              html.push('</tr>');\n              i++;\n            }\n\n            html.push('</tbody></table></div>');\n            i--;\n            continue;\n          }\n          \n          let isUl = /^[-*]\\s+(.+)/.test(content);\n          let isOl = /^\\d+\\.\\s+(.+)/.test(content);\n          \n          if (isUl || isOl) {\n            let listType = isUl ? 'ul' : 'ol';\n            let match = isUl ? content.match(/^[-*]\\s+(.+)/) : content.match(/^\\d+\\.\\s+(.+)/);\n            let itemText = match[1];\n            \n            if (stack.length === 0) {\n              stack.push({ type: listType, indent: indent });\n              html.push('<' + listType + '>');\n            } else {\n              let last = stack[stack.length - 1];\n              \n              if (indent > last.indent) {\n                stack.push({ type: listType, indent: indent });\n                html.push('<' + listType + '>');\n              } else if (indent < last.indent) {\n                while (stack.length > 0 && stack[stack.length - 1].indent > indent) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                }\n                if (stack.length === 0 || stack[stack.length - 1].indent !== indent) {\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                } else if (stack[stack.length - 1].type !== listType) {\n                   let closed = stack.pop();\n                   html.push('</' + closed.type + '>');\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                }\n              } else {\n                if (last.type !== listType) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                  stack.push({ type: listType, indent: indent });\n                  html.push('<' + listType + '>');\n                }\n              }\n            }\n            html.push('<li>' + itemText + '</li>');\n          } else {\n            if (content !== '') {\n               while (stack.length > 0) {\n                 let closed = stack.pop();\n                 html.push('</' + closed.type + '>');\n               }\n            }\n            if (/^(?:---|\\*\\*\\*|___)$/.test(content)) {\n              html.push('<hr>');\n            } else if (/^#{1,4}\\s+/.test(content)) {\n              const headingMatch = content.match(/^(#{1,4})\\s+(.+)$/);\n              if (headingMatch) {\n                const level = headingMatch[1].length;\n                html.push('<h' + level + '>' + headingMatch[2] + '</h' + level + '>');\n              }\n            } else if (content) {\n              html.push(content + '<br>');\n            } else {\n              html.push('<br>');\n            }\n          }\n        }\n        \n        while (stack.length > 0) {\n          let closed = stack.pop();\n          html.push('</' + closed.type + '>');\n        }\n        \n        let result = html.join('')\n          .replace(/!\\[(.*?)\\]\\((.*?)\\)/g, '<img src=\"$2\" alt=\"$1\">')\n          .replace(/\\*\\*(.+?)\\*\\*/g, '<strong>$1</strong>')\n          .replace(/__(.+?)__/g, '<strong>$1</strong>')\n          .replace(/\\*(.+?)\\*/g, '<em>$1</em>')\n          .replace(/_(.+?)_/g, '<em>$1</em>')\n          .replace(/`(.+?)`/g, '<code>$1</code>')\n          .replace(/\\[(.+?)\\]\\((.+?)\\)/g, '<a href=\"$2\" target=\"_blank\">$1</a>');\n        \n        result = result\n          .replace(/<br><ul>/g, '<ul>')\n          .replace(/<br><ol>/g, '<ol>')\n          .replace(/</ul><br>/g, '</ul>')\n          .replace(/</ol><br>/g, '</ol>');\n        \n        return result;\n      }\n\n      document.body.addEventListener('mouseover', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          const note = e.target.dataset.note;\n          if (note) {\n            tooltip.innerHTML = parseNoteMarkdown(note);\n            tooltip.style.display = 'block';\n            const rect = e.target.getBoundingClientRect();\n            const tooltipRect = tooltip.getBoundingClientRect();\n            const pageX = window.scrollX || window.pageXOffset;\n            const pageY = window.scrollY || window.pageYOffset;\n            const maxLeft = pageX + window.innerWidth - tooltipRect.width - 10;\n            const minLeft = pageX + 10;\n\n            let left = rect.left + pageX;\n            if (left > maxLeft) left = maxLeft;\n            if (left < minLeft) left = minLeft;\n\n            let top = rect.bottom + pageY + 6;\n            const maxTop = pageY + window.innerHeight - tooltipRect.height - 10;\n            if (top > maxTop) {\n              top = rect.top + pageY - tooltipRect.height - 6;\n            }\n            if (top < pageY + 10) top = pageY + 10;\n\n            tooltip.style.left = left + 'px';\n            tooltip.style.top = top + 'px';\n          }\n        }\n      });\n\n      document.body.addEventListener('mouseout', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          setTimeout(() => {\n            if (!tooltip.matches(':hover')) {\n              tooltip.style.display = 'none';\n            }\n          }, 100);\n        }\n      });\n\n      tooltip.addEventListener('mouseleave', function() {\n        tooltip.style.display = 'none';\n      });\n    });\n  </script>\n</head>\n<body>\n<blockquote></blockquote><h1 style=\"text-align: center\">Тема 93. Възпалителни заболявания на матката, тръбите и яйчниците. Морфологична характеристика, усложнения.</h1><p>Увод към <strong><span class=\"editor-note\" data-note=\"# **1. Анатомично устройство**\nМаточната шийка е най-долната част на матката (1/3 от дължината ѝ в репродуктивна възраст). Дели се на две части:\n* **Екзоцервикс (Portio vaginalis - PVCU):** Влагалищна част с цилиндрична форма.\n* **Ендоцервикс:** Горна, суправагинална част, съдържаща цервикалния канал (**canalis cervicalis**), който завършва с външно отвърстие (**OECC** - ostium externum canalis cervicalis).\n---\n# **2. Хистологичен строеж (Епител)**\n| Част | Тип епител | Характеристики |\n| :--- | :--- | :--- |\n| **Екзоцервикс** | **Многослоен плосък невроговяващ** | Пролиферацията и съзряването му зависят от **естрогените**. Тънък и атрофичен преди пубертета и в менопауза (слаба бариера). |\n| **Ендоцервикс** | **Еднореден слузопродуциращ цилиндричен** | Светла цитоплазма, базални ядра. Покрива повърхността и инвагинациите. Съдържа и единични невроендокринни клетки. |\n---\n# **3. Сквамозно-цилиндрична връзка (Граница)**\nТова е мястото, където се срещат двата вида епител. Различаваме два типа:\n* **Оригинална граница:** Рязка граница на нивото на външното отвърстие (OECC).\n* **Физиологична (функционална) граница:** Променя се под влияние на хормоните.\n---\n# **4. Ектопия (Ектропион) и Зона на трансформация**\n## **Ектопия (Ectropion / Eversio)**\n* **Механизъм:** Под влияние на естрогените (в репродуктивна възраст) обемът на шийката нараства, ендоцервикалната мукоза се &quot;подава&quot; навън и жлезистият епител се установява върху ектоцервикса.\n* **Макроскопски:** Изглежда яркочервено (клиничен термин: *erosio*), контрастиращо на розовия сквамозен епител. Това е **нормално физиологично явление**.\n## **Зона на трансформация (ZT)**\n* **Дефиниция:** Участъкът, в който ектропионът се реепителизира със сквамозен епител.\n* **Клинично значение:** Това е най-важната зона, тъй като в нея възникват **90% от сквамозните карциноми** на маточната шийка.\n* **В менопауза:** Поради намаления обем на шийката, зоната на трансформация се измества навътре в канала и става **невидима** при колпоскопия.\" id=\"note-1776598201374-5\">анатомия</span></strong> на маточната шийка със <strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-19/text-editor-images/2026/04/1776598179221-image.png &quot;width=100%&quot;)\" id=\"note-1776598209938-6\">схематично представяне</span></strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Възпалителни заболявания на маточната шийка (Цервицити)</h2><h3>Неинфекциозен цервицит</h3><p>Причинява се предимно от механични и химични фактори:</p><ul><li>Травми от чужди тела (тампони, диафрагми, песари, вътрематочни спирали).</li><li>Извършване на медицински манипулации.</li></ul><p><strong>Остър неинфекциозен цервицит</strong></p><ul><li><strong>Макроскопски:</strong> Маточната шийка е зачервена и оточна; възможна гнойна ексудация от цервикалния канал.</li><li><strong>Микроскопски:</strong> Кръвонапълнени съдове, оток в стромата, наличие на неутрофилни левкоцити в епитела и стромата.</li><li><strong>Усложнения:</strong> При тежко протичане – дегенеративни промени в епителните клетки и улцерации.</li></ul><p><strong>Хроничен неинфекциозен цервицит</strong></p><ul><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-19/text-editor-images/2026/04/1776597661163-image.png &quot;width=100%&quot;)\" id=\"note-1776597662935-0\">Макроскопски</span>:</strong> Хиперемия на мукозата и огнищни улцерации.</li><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-19/text-editor-images/2026/04/1776597671680-image.png &quot;width=100%&quot;)\" id=\"note-1776597673410-1\">Микроскопски</span>:</strong> Кръглоклетъчна инфилтрация, понякога с оформяне на лимфни фоликули, гранулационна тъкан и субепителна фиброза.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Инфекциозни цервицити</h2><h3>Бактериален цервицит</h3><p>Честа инфекция при жени в репродуктивна възраст, често протичаща латентно. Засяга предимно лигавицата на ендоцервикса.</p><ul><li><strong>Етиология:</strong> Най-чест причинител е <em><strong>Chlamydia trachomatis</strong></em><strong> </strong>(доказва се при 1-3% от всички жени и 40% от жените със сексуално-трансмисивни инфекции).</li><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-19/text-editor-images/2026/04/1776598252014-image.png &quot;width=100%&quot;)\" id=\"note-1776598253292-7\">Клиника</span>:</strong> Жълто-зелена мукопурулентна ексудация от ендоцервикса.</li><li><strong>Микроскопски:</strong> Възпалителен процес с оформяне на лимфни фоликули субепително (<strong>фоликуларен цервицит</strong>). Може да се наблюдава реактивен плоскоклетъчен и жлезен атипизъм (до CIN I).</li><li><strong>Диагноза: </strong>Хламидийна инфекция може да се подозира при фоликуларен цервицит, а се доказва чрез имунохистохимични (имунофлуоресцентни или имунопероксидазни) методи с прилагане на моноклонални антитела или с клетъчни култури.</li></ul><h3>Вирусни цервицити</h3><p>За разлика от бактериалните, те засягат предимно сквамозния епител на ектоцервикса.</p><p><strong>Херпесен цервицит (HSV)</strong></p><ul><li><strong>Етиология:</strong> Причинява се главно от <strong><em>HSV тип 2</em> </strong>(<strong>genitalis</strong>), предаван по сексуален път. Болшинството първично инфектирани жени са под 20-годишна възраст. Възможно е и от от HPV, но той ще се разглежда при псевдотуморни и туморните заболявания на цервикса.</li><li><strong>Клиника:</strong> Силна болка, чувствителност по външните полови органи, диспареуния, профузно бистро влагалищно течение.</li><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-19/text-editor-images/2026/04/1776598312108-image.png &quot;width=60%&quot;)\" id=\"note-1776598368622-10\">Макроскопски</span>:</strong> Множество везикули, преминаващи в улцерации върху хиперемирана основа по вулвата, перинеума, влагалището и маточната шийка. В тежки случаи улцеро-некротичните промени наподобяват разпадаща се туморна маса.</li><li><strong><span class=\"editor-note\" data-note=\"![Image](https://static.framar.bg/thumbs/6/pathology/klinichna-patologiq-herpes-simpleks-ifekciq.jpg &quot;width=100%&quot;)\" id=\"note-1776598356374-9\">Микроскопски</span>:</strong> <p>Във везикулозния стадий се виждат </p>супрабазални интраепидермални мехурчета, дегенерирали епителни клетки и <strong>гигантски многоядрени клетки</strong>, които понякога съдържат <strong>вътреядрени еозинофилни включвания (<p>Телца на Каудри тип А)</p></strong>, обградени със светло хало от хроматина.</li><li><strong>Диагноза:</strong> Цитология, серология и клетъчни култури.</li></ul><p><strong>Значение и усложнения на вирусните инфекции:</strong></p><ul><li>Риск от спонтанен аборт или смърт на плода.</li><li>Интрапартална инфекция на новороденото.</li><li>Потенциална роля в генезата на рак на маточната шийка.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Възпалителни заболявания на маточното тяло (Ендометрити)</h2><h3>Остър ендометрит</h3><ul><li><strong>Етиология:</strong> Най-често се причинява от хемолитични стрептококи, стафилококи, <em>Neisseria gonorrhoeae</em> и клостридии. Инфекцията обикновено прониква асцендентно от маточната шийка след аборт, раждане или медицински манипулации, свързани с дилатиране на цервикалния канал. По-рядко може да възникне по хематогенен път или десцендентно от инфектирани маточни тръби.</li><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-19/text-editor-images/2026/04/1776598620149-image.png &quot;width=100%&quot;)\" id=\"note-1776598621949-11\">Морфологична характеристика</span>:</strong> В стромата на ендометриума се формират <strong>микроабсцеси</strong>, а лумените на жлезите се изпълват с <strong>неутрофили</strong>.</li></ul><h3>Хроничен ендометрит</h3><ul><li><strong>Етиология:</strong>&nbsp;<p>Основните причинители са <em>Chlamydia trachomatis</em> и <i>Neisseria gonorrhoeae. </i></p><p>Установява се при 3-10% от жените с патологични маточни кървения.</p></li><li><p><strong>Рискови фактори:</strong> Прекаран аборт, наличие на вътрематочни спирали (IUD) или остатъци от некротични тъкани в матката (например инфарциран полип, некротичен тумор).</p></li><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-19/text-editor-images/2026/04/1776598860986-image.png &quot;width=100%&quot;)\" id=\"note-1776598862017-13\">Микроскопски</span>:</strong> Характеризира се с инфилтрат от лимфоцити, <strong>плазматични клетки </strong>и макрофаги. Типичен белег е липсата на синхрон в съзряването на ендометриалните жлези — някои са с недобре изразени фазови промени, други остават в пролиферативна фаза, докато други показват белези на секреция. Стромалните клетки често се подреждат концентрично около жлезите.</li></ul><h4>Туберкулозен ендометрит</h4><p>Това е специфично хронично грануломатозно възпаление, което обикновено се развива десцендентно при наличие на туберкулозен салпингит. </p><p><strong>Диагноза</strong>: Трудна, тъй като за формирането на характерните „цветущи“ туберкули са необходими около 2 седмици, а функционалният слой на ендометриума се подменя на всеки 4 седмици. Поради това кюретажът трябва да се извършва в късната секреторна фаза на или в десквамативната фаза на цикъла.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Възпалителни заболявания на маточните тръби (Салпингити)</h2><h4>Остър салпингит</h4><p>Това е остър, обикновено двустранен възпалителен процес. Най-често възниква при венерически заболявания, в пуерпериума, след аборт, вторично при остър апендицит или по хематогенен път.</p><ul><li><strong>Етиология: </strong>Най-чести причинители са <em>Chlamydia trachomatis</em> и <em>Neisseria gonorrhoeae</em>, по-рядко <em>Bacteroides</em> и микоплазми.</li><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-19/text-editor-images/2026/04/1776598753002-image.png &quot;width=100%&quot;)\" id=\"note-1776598754052-12\">Макроскопски</span>:</strong> Маточните тръби са разширени, лумените им (особено в ампуларните части) са изпълнени с гноен ексудат. Серозата е зачервена и покрита с гноен налеп. Може да се наблюдават огнищни гнойни колекции (тубоовариални абсцеси).</li><li><strong>Микроскопски:</strong> Луменът е изпълнен с неутрофилни левкоцити, които инфилтрират мукозата и цялата стена на тръбата.</li><li><strong>Изход:&nbsp;</strong>Често процесът хронифицира.</li></ul><h3>Хроничен салпингит</h3><p>Развива се около 10 дни след остър салпингит.</p><ul><li><strong>Макроскопски:</strong> Стената на маточната тръба е задебелена. В лумена се установява гной (дифузно или в малки кистички между сраснали гънки). Характерни са адхезии в самия лумен, както и между тръбата и яйчниците.</li><li><strong>Микроскопски:</strong> Възпалителният ексудат е съставен предимно от плазматични клетки, макрофаги, лимфоцити и неутрофилни левкоцити.</li><li><strong>Клинично значение: </strong>Срастванията и стесняването на лумена на маточната тръба могат да доведат до <strong>стерилитет </strong>или <strong>тубарна бременност.</strong></li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Възпалителни заболявания на яйчниците (Оофорити)</h2><h3>Бактериални инфекции</h3><ul><li><strong>Етиология</strong>: Обикновено възникват вторично, като разпространение на възпалителен процес от салпингит. Причинителите са най-често <em>Neisseria gonorrhoeae</em>, <em>Chlamydia trachomatis</em> и <em>Mycoplasma hominis</em>. Флората обикновено е смесена с преобладаване на анаеробни микроорганизми.</li><li><strong>Клиника</strong>: Протича с болка в таза (често едностранна), повишена температура, понякога кървене или наличие на бяло течение от влагалището.</li><li><strong><span class=\"editor-note\" data-note=\"![Image](https://cdn.discordapp.com/attachments/1178611691076997130/1495424086074196168/image.png?ex=69e631b5&amp;is=69e4e035&amp;hm=8ef120ad689a4d44ad73920c95bd55edbe24a2bc40f85d0968553ffe3097abeb&amp;animated=true &quot;width=100%&quot;)\" id=\"note-1776598897312-14\">Макроскопски</span></strong>: Процесът често е едностранен и води до формиране на <strong>тубоовариален абсцес</strong>. При него яйчникът и маточната тръба са уголемени и прираснали в обща мековата маса. На срез се виждат кухини с мека стена, покрита с жълто-зелен налеп и изпълнени с гной. По-рядко (например при апендицит) може да се засегне само яйчникът и да се образува изолиран абсцес.</li><li><strong>Микроскопски</strong>: Кухината съдържа гноен ексудат, а стената на абсцеса е изградена от гранулационна тъкан.</li><li><strong>Протичане и усложнения</strong>: Възможна е руптура на абсцеса в перитонеалната кухина с последващ <strong>перитонит</strong>. Друго усложнение е обхващането на съседни органи (дебело черво, пикочен мехур, влагалище) и образуване на <strong>фистули</strong>.</li></ul><h3>Ксантогрануломатозен оофорит (рядка хронична форма)</h3><ul><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-19/text-editor-images/2026/04/1776598979833-image.png &quot;width=100%&quot;)\" id=\"note-1776598981412-15\">Макроскопски</span></strong>: Образува се солидна, лобулирана тумороподобна маса с жълто-оранжев цвят и диаметър 5-10 cm.</li><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-19/text-editor-images/2026/04/1776598986241-image.png &quot;width=100%&quot;)\" id=\"note-1776598987237-16\">Микроскопски</span></strong>: Установяват се множество <strong>пенести клетки</strong>, примесени с гигантски многоядрени клетки, плазмоцити, фибробласти, неутрофилни левкоцити и огнищни некрози.</li></ul><h3>Актиномикоза</h3><ul><li><strong>Етиология</strong>: Обикновено е усложнение при употреба на <strong>вътрематочни </strong><strong>спирали</strong>. Засягането на аднексите най-често е едностранно.</li><li><strong>Макроскопски</strong>: Характеризира се с наличието на множество конфлуиращи абсцеси в яйчника. (заболяването е описано в клинична патология на инфекциозните заболявание).</li></ul><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><br><br><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center; transition: background-color 0.3s; background-color: rgba(88, 129, 87, 0.15)\">Тема 94. Хиперплазия на ендометриума. Същност. Морфология</h1><h2>Същност и етиология</h2><p><strong>Хиперплазията на ендометриума</strong> представлява патологична <strong>пролиферация на ендометриални жлези</strong> с неправилна форма и твърде различни размери. Основният диагностичен критерий е <strong>увеличението на индекса жлези/строма</strong> в сравнение с нормалния пролиферативен ендометриум. </p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Обикновена (проста) хиперплазия</h2><ul><li><strong>Етиология</strong>: Състоянието е пряк резултат от продължително и некомпенсирано стимулиране на ендометриума с <strong>естрогени</strong>. Липсва антипролиферативният ефект на <strong>прогестерона</strong>, който нормално прекъсва този процес. Типичен фон за развитието ѝ са редуващите се <strong>ановулаторни цикли</strong>, характерни за жени в репродуктивна възраст.</li><li><strong>Клиника</strong>: Най-често засяга жени във възрастовата група между 40 и 50 години. Клиничната картина включва периоди на <strong>аменорея </strong>с различна продължителност, които биват последвани от неправилни и обилни кръвотечения (<strong>менометрорагии</strong>).</li><li><strong>Макроскопски</strong>: Целият ендометриум изглежда задебелен, като на места може да придобие полиповиден или кадифен изглед. Наблюдават се огнищни кръвоизливи и малки кистички по повърхността. Под системното влияние на естрогените самият миометриум също често е леко задебелен и хипертрофичен.</li><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-19/text-editor-images/2026/04/1776599148263-image.png &quot;width=100%&quot;)\" id=\"note-1776599149160-18\">Микроскопски</span>:</strong></li><ul><li><strong>Разпространение</strong>: Процесът е <strong>дифузен </strong>както по ширина, така и в дълбочина, като характерната граница между функционалната и базалната зона на ендометриума е напълно заличена.</li><li><strong>Жлези</strong>: Установяват се жлези с изразено вариращи размери – някои са кистично разширени, други са с нормален размер, а трети са по-малки от обичайното. Те обикновено са окръглени, с правилни и гладки граници. Рядко се забелязват малки епителни вдавания в околната строма.</li><li><strong>Епител</strong>: Жлезистият епител е тапициран е от цилиндрични клетки с интензивно базофилна цитоплазма. Ядрата са разположени базално или централно. Често се наблюдава псевдостратификация или истинска стратификация на клетките, както и образувания, подобни на „туфи“, обърнати към лумените. <strong>Важно: не се открива клетъчен или ядрен атипизъм.</strong></li><li><strong>Строма и съдове</strong>: Стромата е подчертано хиперцелуларна. В нея и в жлезите се откриват нормални митози. Могат да се видят дилатирани и на места тромбозирани синусоиди, малки некрози и възпалителни огнища.</li></ul></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Атипична хиперплазия на ендометриума</h2><ul><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-19/text-editor-images/2026/04/1776599240022-image.png &quot;width=100%&quot;)\" id=\"note-1776599241103-19\">Микроскопски</span></strong>: За разлика от простата хиперплазия, атипичната има <strong>огнищен характер</strong>. В съседство с атипичните зони ендометриумът може да бъде нормален, атрофичен или с проста хиперплазия. Атипизмът бива два вида, които често се съчетават:</li><ul><li><strong>Хистологичен (структурен) атипизъм</strong>: Проявява се в това, че жлезите са твърде големи, многобройни и силно „наблъскани“ с минимално количество строма между тях. Епителът е силно разраснал и образува множество вдавания навън към лумена (туфи, папили).</li><li><strong>Цитологичен (клетъчен) атипизъм</strong>: Може да бъде огнищен или мултифокален. Характеризира се с увеличен ядрено-цитоплазмен индекс, нарушен ядрен поларитет и увеличени нуклеоли. Хроматинът може да бъде струпан или пръснат (т.нар. „светли ядра“). Различават се леки, умерени (най-чести) и тежки форми.</li></ul><li><strong>Диференциална диагноза</strong>: Основно предизвикателство е разграничаването на тежката атипична хиперплазия от високодиференциран рак на ендометриума. Признаци, говорещи за <strong>карцином</strong>, са:</li><ol><li>Изпълване на жлезните лумени с епител (без папиларни структури).</li><li>Наличие на ядрени отломки и полинуклеари в лумените.</li><li>Атипични митози.</li><li>Пълна липса на строма между жлезите (back-to-back).</li><li>Обширни зони от недиференциран епител.</li></ol><li><strong>Прогноза и значение</strong>: Атипичната хиперплазия се счита за <strong>преканцероза</strong>. Тя може да съществува със или без естрогенна стимулация. Статистически в около 10% от случаите тя прогресира до рак. Рискът зависи силно от вида атипизъм:</li><ul><li>Само хистологичен атипизъм: риск под 2%.</li><li>Наличие на <strong>клетъчен атипизъм</strong>: рискът от развитие на рак скача на <strong>23%</strong>.</li></ul></ul><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><br><br><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center; transition: background-color 0.3s\">Тема 95. Ерозии на маточната шийка. Цервикална интраепителна неоплазия.</h1><h2>Ерозии на маточната шийка (Ектопия и ектропион)</h2><p>Маточната шийка анатомично се разделя на две основни части: <strong>екзоцервикс</strong>, покрит с многослоен плосък невроговяващ епител, и <strong>ендоцервикс</strong>, покрит с еднореден цилиндричен епител. Мястото, където тези два вида епител се срещат, се дефинира като <strong>сквамозно-цилиндрична граница</strong>.</p><p>Под влияние на естрогените при жените в репродуктивна възраст обемът на маточната шийка се увеличава, което води до \"подаване\" на част от ендоцервикалната мукоза към влагалището. Това състояние се обозначава като <strong>ектопия</strong> или <strong>ектропион</strong> и представлява нормално физиологично явление. Тъй като тези участъци са с яркочервен цвят, те контрастират силно на бледорозовия фон на плоския епител, което е довело до широкото използване на клиничния термин <strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-19/text-editor-images/2026/04/1776599369382-image.png &quot;width=100%&quot;)\" id=\"note-1776599370491-20\">ерозия</span></strong>.</p><p>С течение на времето ектропионът се реепителизира с плосък епител, при което се формира т.нар. <strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-19/text-editor-images/2026/04/1776599389683-image.png &quot;width=100%&quot;)\" id=\"note-1776599390945-21\">зона на трансформация</span></strong>. Тази зона има изключително клинично значение, тъй като в нея възникват около <strong>90% от сквамозните карциноми</strong> на маточната шийка. У жените в менопауза тази зона обикновено се измества навътре в цервикалния канал, като по този начин става невидима при колпоскопско изследване.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Интраепителна неоплазия на маточната шийка (ЦИН / CIN)</h2><p><strong>Синоними</strong>: Дисплазия на маточната шийка, Сквамозна интраепителна лезия (СИЛ / SIL).</p><h3>Същност на процеса</h3><p>Цервикалната интраепителна неоплазия отразява процес, при който пролифериращите резервни клетки не съзряват и не се диференцират в нормален сквамозен епител. Те се превръщат в клетки, които морфологично и биологично отговарят на раковите, но <strong>нямат капацитет да инвазират</strong> (да преминат през базалната мембрана в стромата).</p><h3><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-19/text-editor-images/2026/04/1776599515522-image.png &quot;width=70%&quot;)\" id=\"note-1776599472572-22\">Класификация</span></h3><p>Процесът се разделя на три основни степени според дебелината на засегнатия епителен слой:</p><ul><li><strong>Лека дисплазия (I степен / CIN I)</strong>: Измененията са ограничени само в долната 1/3 на сквамозния епител (близо до базалната мембрана).</li><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-19/text-editor-images/2026/04/1776610441343-image.png &quot;width=100%&quot;)\" id=\"note-1776610442522-0\">Умерена дисплазия</span> (II степен / CIN II)</strong>: Диспластичните промени обхващат долните 2/3 от дебелината на епитела.</li><li><strong>Тежка дисплазия (III степен / CIN III)</strong>: Почти всички слоеве са изградени от диспластични клетки, като само в най-повърхностните слоеве могат да се открият единични диференцирани клетки.</li><li><strong>Carcinoma in situ</strong>: Всички клетки в целия слой на епитела са анапластични (ракови).</li></ul><h3>Етиология и разпространение</h3><ul><li><strong>Честота</strong>: Засяга около 1% от жените, предимно в млада възраст (средно 30 години).</li><li><strong>Рискови фактори</strong>: Свързват се основно със сексуалния живот – ранно начало, честа смяна на партньори, много бременности с кратък интервал, ниска полова хигиена.</li><li><strong>Вирусна инфекция</strong>: Ключово значение има инфекцията с <strong>HSV 2</strong> (Herpes simplex virus) и HPV. Вирусът се доказва често в клетките на ЦИН, а при жени с антитела спрямо него рискът е 7 пъти по-висок. Особено чувствителни са клетките в зоната на трансформация в млада възраст.</li></ul><h3>Клинична картина и диагностика</h3><ul><li>Интраепителната неоплазия <strong>няма субективна симптоматика</strong>.</li><li><strong>Диагноза</strong>: Поставя се сигурно само чрез хистологично изследване. Насочващи методи са колпоскопията и цитологичното изследване (цитонамазка).</li></ul><h3>Микроскопска характеристика</h3><ul><li><strong>Локализация</strong>: Започва най-често от сквамозно-цилиндричната граница на преходната зона и е рязко демаркиран от непроменения епител.</li><li><strong>Промени в епитела</strong>: Нарушена е нормалната ритмична слоистост на епителя и кохезия между клетките. Настъпва пълна дезорганизация – клетките губят своя поляритет и са хаотично разположени.</li><li><strong>Клетъчни промени</strong>: Ядрата са с различна форма и размер (полиморфизъм), хиперхромни, с увеличен ядрено-цитоплазмен индекс. Намалява количеството на гликоген в цитоплазмата. Намират се множество, често неправилни митози в засегнатата зона.</li></ul><h3>Прогноза и изход</h3><p>Дисплазията е междинно звено към инвазивния рак. Съществува възможност за преминаване от по-ниска към по-висока степен на дисплазия. Рискът от инвазия е правопропорционален на тежестта на дисплазията, но тя може да настъпи и при по-леки форми.</p><h3>Лечение</h3><ul><li><strong>Леки форми</strong>: Консервативно лечение и редовен контрол (цитология и колпоскопия).</li><li><strong>Тежки форми</strong>: Изискват оперативна биопсия чрез <strong>конизация</strong> (изрязване на „конус“ от маточната шийка). </li><li><strong>Критични условия</strong>: Хистологичното изследване на конуса трябва категорично да изключи инвазия и да потвърди, че промените не достигат до ръбовете на изрязаната тъкан („изрязване в здраво“). Ако тези условия не са изпълнени, се налага хистеректомия.</li></ul><hr data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><br></p><p><br></p><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center; transition: background-color 0.3s\">Тема 96. Тумори на маточната шийка. Морфологична характеристика.</h1><h2>Псевдотумори</h2><h3>1.Ендоцервикални полипи</h3><p><strong>Ендоцервикалните полипи</strong> представляват най-честите доброкачествени образувания на маточната шийка, които се срещат предимно при многораждали жени на възраст между 40 и 60 години. Те се дефинират като огнищни, хиперпластични разраствания на епитела и подлежащата строма на ендоцервикалните гънки. Нямат изяснена етиология.</p><p><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-19/text-editor-images/2026/04/1776608410798-image.png &quot;width=100%&quot;)\" id=\"note-1776599725502-23\">Макроскопски</span></strong> полипите са окръглени или удължени мековати образувания с гладка или лобулирана повърхност. Размерите им варират от няколко милиметра до 2–3 cm, като в редки случаи могат да бъдат и по-големи, изпълвайки цервикалния канал или подавайки се през външния му отвор във влагалището. Обикновено са с <strong>жълто-охрен цвят</strong>.</p><p><strong><span class=\"editor-note\" data-note=\"На това изображение на цервикалната лигавица се виждат типични ендоцервикални жлези с оточна строма и изразена конгестия.\n![Image](https://www.ncbi.nlm.nih.gov/books/NBK560709/bin/nevus12.jpg &quot;width=100%&quot;)\" id=\"note-1776599777046-24\">Микроскопски</span></strong> полипите са изградени от цилиндричен епител и фиброваскуларна строма. В зависимост от преобладаващата съставка се различават жлезисти (най-чести), фиброзни и васкуларни полипи. В стромата често се установява възпалителна инфилтрация, която при висока интензивност води до формиране на гранулационна тъкан. Покривният епител може да претърпи <strong>плоскоклетъчна метаплазия</strong>, особено в областта на върха на полипа. По време на бременност в стромата може да настъпят огнищни децидуални промени - децидуален полип.</p><p><strong>Клинично </strong>се симптоми са кървене и левкорея, които се причиняват съответно от разязвяване на повърхностния епител и хиперсекреция на слуз от възпаления ендоцервикален епител</p><h3>2. Кондиломи на маточната шийка</h3><p><strong>Кондиломите</strong> са папиларни разраствания на сквамозния епител, причинени от инфекция с <strong>Human papilloma virus (HPV)</strong>. \n<strong>Макроскопски </strong>те се разделят на три основни форми:</p><ol><li><strong>Плоски кондиломи:</strong> Съставляват до 90% от случаите и често не са добре видими при обикновен преглед. Представляват леко надигнати, добре ограничени плаки с неправилна форма, които стават ясно различими и бели след третиране с оцетна киселина.</li><li><strong>Остри кондиломи:</strong> Срещат се много по-рядко. Характерни са за многослойния плосък вроговяващ епител на перинеума и вулвата.</li><li><strong>Макуло-папулозни кондиломи:</strong> Множество малки образувания, обхващащи влагалището и шийката.</li></ol><p><strong><span class=\"editor-note\" data-note=\"![Image](https://apps.uworld.com/media/L66002.jpg &quot;width=100%&quot;)\" id=\"note-1776599918419-25\">Микроскопски</span></strong> най-характерните черти са:</p><ul><li><strong></strong><span class=\"editor-note\" data-note=\"![Image](https://apps.uworld.com/media/L6085.jpg &quot;width=100%&quot;)\" id=\"note-1776599949506-26\"><strong>К</strong><strong>ойлоцитозата</strong></span><strong></strong> (ядрен атипизъм и перинуклеарно просветляване в зреещите клетки), което е израз на вирусния цитопатичен ефект.&nbsp;</li><li>Нарушена архитектоника на епитела - хиперплазия с акантоза и папиломатоза</li><li>Промени в епителните клетки - анизоцитоза, пикноза или хиперхромазия на ядрата.</li><li>Абнормално изразена кератинизация - както дискератоза, така и хипер- и паракератоза.</li></ul><p><strong>Диагноза </strong>се прави след доказване на вътреядрено разположените вириони чрез електронномикроскопско и имунихистохимично изследване и чрез in situ хибридизация.\n<strong>Прогноза. </strong>Прогресия в CIN и микроинвазивен карцином се наблюдава в около 10% от болните. При бременност се наблюдават рецидиви на кондиломите, както и увеличаване на броя им, а след раждане изчезват. Възможно е и вертикално предаване на инфекцията (на плода и новороденото).</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Злокачествени тумори на маточната шийка</h2><h3>1. Микроинвазивен спиноцелуларен карцином (Стадий IA)</h3><p>За <strong>микроинвазивен карцином</strong> се приема този рак, при който инвазията в стромата е ограничена до 1 mm, 3 mm или 5 mm (според различните класификации), измервано от базалната мембрана на епитела на повърхностния епител обхванат от ЦИН.\n<strong>Клинично</strong> заболяването протича напълно безсимптомно и макроскопската картина не е характерна. Диагнозата се поставя единствено чрез <strong>хистологично изследване</strong>. При него се установява разкъсване на базалната мембрана от проникнали в стромата туморни повлекла с остър връх. В съседство на зоната на инвазия винаги се откриват участъци с цервикална интраепителна неоплазия (ЦИН).</p><h3>2. Инвазивен спиноцелуларен (плоскоклетъчен) карцином на маточната шийка</h3><ul><li><strong>Честота и разпространение</strong>: Това е най-честият малигнен генитален тумор при жените (съставлява 80% от карциномите на шийката). Най-засегнати са жените между 35 и 50 години като е сред четирите причини за смърт от малигнен тумор (заедно с този на гърдата, белите дробове и дебелото черво). Благодарение на профилактичните цитологични изследвания (цитонамазки), честотата му е спаднала драстично в последните десетилетия. Средната възраст на диагностициране е 50 години.</li><li><strong>Клиника</strong>: Основен симптом са неправилните маточни кръвотечения – както спонтанни, така и контактни (след полов акт). Течението може да бъде серо-сангвинолентно (воднисто-кърваво) или гнилостно с неприятна миризма. Рядко има ирадииращи към сакрума болки. Общи прояви настъпват в много напредналите случаи.</li><li><strong>Макроскопски форми</strong>: Туморът започва най-често в зоната на трансформация като малка язвичка или уплътнена, неравна и лесно кървяща при допир зона. Различават се две основни форми:</li><ul><li><strong>Екзофитна</strong>: Расте навън към лумена на влагалището, има полиповиден или папиларен вид.</li><li><strong>Ендофитна</strong>: Расте навътре към тъканта на шийката, често е улцероинвазивна.</li></ul><li><strong>Клинични стадии:</strong></li><ul><li><strong>Стадий 0</strong>: Carcinoma in situ.</li><li><strong>Стадий I</strong>: Ракът е ограничен само в маточната шийка.</li><li><strong>Стадий II</strong>: Разпространение извън шийката в горните 2/3 на влагалището или параметриумите (без да стига тазовата стена).</li><li><strong>Стадий III</strong>: Достига до долната третина на влагалището и/или тазовата стена.</li><li><strong>Стадий IV</strong>: Обхваща съседни органи (пикочен мехур, ректум) или дава далечни метастази.</li></ul><li><strong>Микроскопски</strong>: Според степента на диференциация бива високо, умерено или ниско диференциран. Клетъчните типове според преобладаващия клетъчен тип биват едроклетъчен вроговяващ, едроклетъчен невроговяващ и дребноклетъчен.</li><ul><li><p><strong>Едроклетъчен вроговяващ</strong>: Характеризира се с наличие на кератинови (<strong>ракови</strong>) <strong>перли </strong>и междуклетъчни мостчета. Това е най-високо диференцираната форма, при която клетките запазват способността си да произвеждат кератин.</p><br></li></ul><li><strong>Разпространение:&nbsp;</strong>Разпространява се чрез директно прорастване, по лимфен и по хематогенен път.</li><li><strong>Лечение:</strong>&nbsp;Радикална хистеректомия и лъчетерапия.</li><li><strong>Прогноза</strong>: Зависи пряко от стадия – при I стадий 5-годишната преживяемост е до 90%, докато при III стадий пада на 30-35%.</li></ul><h3>3. Аденокарцином на маточната шийка</h3><ul><li><strong>Честота</strong>: Представлява около 5% от карциномите на маточната шийка. Среща се при малко по-възрастни жени в сравнение със сквамозния рак.</li><li><strong>Макроскопски</strong>: В 15% от случаите е <strong>ендофитен</strong> (невидим при преглед), а в останалите случаи има папиларен вид, полипозно-папиларен, приличащ на цветно зеле или гъба.</li><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-19/text-editor-images/2026/04/1776600105406-image.png &quot;width=100%&quot;)\" id=\"note-1776600106949-27\">Микроскопски</span></strong>: Най-често е <strong>муцинозен аденокарцином </strong>с различна степен на диференциация. Срещат се и по-редки форми като светлоклетъчен, аденосквамозен и аденоидокистичен рак.</li><li><strong>Прогноза</strong>: По-лоша в сравнение с плоскоклетъчния рак, тъй като метастазира по-рано.</li></ul><hr data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><br><br><hr data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center; transition: background-color 0.3s\">Тема 97. Тумори на маточното тяло. Морфологична характеристика.</h1><h2>Ендометриални полипи</h2><p>Ендометриалните полипи представляват <strong>доброкачествени </strong>разраствания на лигавицата на матката, които съдържат жлези, строма и кръвоносни съдове в променливи съотношения. Те се срещат най-често при жени на възраст между <strong>40 и 50 години</strong> и клинично се проявяват с неправилни маточни кръвотечения и по-рядко със стерилитет. Рискът от развитие на злокачествен процес в тях е минимален.</p><h3><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-19/text-editor-images/2026/04/1776600178374-image.png &quot;width=100%&quot;)\" id=\"note-1776600179533-28\">Макроскопска характеристика</span></h3><p>Полипите обикновено са единични, но в около 20% от случаите могат да бъдат множествени. Размерите им варират от съвсем малки формации до огромни структури, които преминават през цервикалния канал във влагалището. Те могат да изхождат на <strong>краче</strong> или да са прикрепени на широка основа, като най-често се локализират в областта на фундуса и маточните рогове. Повърхността им е гладка и блестяща, със специфичен <strong>жълто-охрен цвят</strong>.</p><h3>Микроскопски видове</h3><p>Различават се три основни вида полипи:</p><ul><li><strong>Функционални:</strong> Най-редкият тип, при който жлезите претърпяват циклични промени, съвпадащи с тези на околния ендометриум.</li><li><strong>Хиперпластични:</strong> Изградени са от хиперпластични и кистично разширени жлези.</li><li><strong>Атрофични:</strong> Срещат се предимно у жени в менопауза; жлезите са атрофични, кистично разширени и са покрити с нискоцилиндричен или кубичен епител.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Ендометриален карцином</h2><h3>Честота и разпространение</h3><p>Ендометриалният рак се превръща в най-честия малигнен тумор на женската полова система, измествайки рака на маточната шийка в много развити страни. Основните причини за това са:</p><ul><li><strong>Демографски фактори:</strong> Удължаването на живота (заболяването е типично за възрастта между <strong>50 и 70 години</strong>).</li><li><strong>Естрогенова стимулация:</strong> Безразборното или продължително прилагане на естрогени без прогестеронова опозиция е основен канцерогенен механизъм.</li><li><strong>Рисков профил:</strong> Жени със затлъстяване, стерилитет, нисък паритет и ановулаторни цикли.</li><li><strong>Съпътстващи заболявания:</strong> Хормонопродуциращи тумори на яйчника или хипертекоза на яйчниковата строма.</li><li><strong>Генетика:</strong> Наблюдава се фамилна обремененост (майки, сестри, лели).</li></ul><h3>Клинична картина</h3><p>Клиничните прояви често са дискретни в началото:</p><ul><li><strong>Патологично кървене:</strong> Мено- и метрорагии. В менопаузата всяко кръвотечение е суспектно за рак (доказва се в близо 50% от случаите).</li><li><strong>Специфично течение:</strong> Белезникаво, кафеникаво или гноевидно (при разпад на тумора).</li><li><strong>Общи симптоми:</strong> Болки в таза, безапетитие, отслабване и анемия се наблюдават само в напреднали стадии.</li></ul><h3>Макроскопски форми</h3><p>Различават се две основни форми на растеж:</p><ol><li><strong>Дифузна форма:</strong> Засяга целия ендометриум, който е силно задебелен, полиповиден, белезникав и трошлив. Често се наблюдават огнища на некроза и кръвоизливи.</li><li><strong>Ограничена форма:</strong> Процесът е локализиран под формата на един или няколко туморни полипа.</li></ol><p><strong>Посока на растеж:</strong></p><ul><li><strong>Екзофитен:</strong> Туморът изпълва маточната кухина, като инвазията в миометриума е повърхностна.</li><li><strong>Ендофитен:</strong> Туморните маси в кухината са оскъдни, но маточната стена е инфилтрирана дълбоко.</li></ul><p>Процесът обикновено започва в горната трета на матката и десцендира към шийката.</p><h3>Микроскопска картина</h3><p>Най-честият хистологичен вариант е <strong>аденокарцином</strong>. Степента на диференциация (grading) се определя според жлезната архитектоника, ядрения атипизъм и митозите:</p><ul><li><strong>I степен:</strong> Високо диференциран.</li><li><strong>II степен:</strong> Умерено диференциран.</li><li><strong>III степен:</strong> Ниско диференциран.</li></ul><p>По-редки форми са плоскоклетъчният карцином (възникващ след метаплазия) и недиференцираният карцином.</p><h3>Аденокарцином</h3><p><strong>Макроскопски белези\n</strong>Туморът се характеризира с преобладаване на <strong>жлезисти</strong> (по-често) или <strong>папиларни</strong> структури. В добре диференцираните си форми жлезите наподобяват тези при пролиферативен ендометриум или хиперплазия.\n<strong>Микроскопски белези\n</strong>С понижаване на диференциацията на карцинома се наблюдават следните промени:</p><ul><li><strong>Индекс жлези/строма:</strong> Прогресивно нарастване (жлезите стават по-гъсти).</li><li><strong>Архитектоника:</strong> Жлезите са хаотично пръснати, разнообразни по форма и силно разклонени.</li><li><strong>Структури:</strong> Поява на <strong>крибриформени </strong>(решетъчни) полета или жлези, изцяло запълнени с епител.</li><li><strong>Солидни участъци:</strong> Нарастване на обширните полета от малигнен епител.</li></ul><p>Честа находка е наличието на <strong>сквамозен епител</strong>, който разраства както вътре в самите жлези, така и в околната строма.</p><h3>Изход и прогноза</h3><p>Ендометриалният рак се разпространява <strong>бавно</strong>, дава метастази на късен етап и има относително добра прогноза.\n<strong>Пътища на разпространение:</strong></p><ol><li><strong>Прорастване (per continuitatem):</strong> Към маточната кухина, шийката, миометриума и достигане до серозата (инвазия на съседни тъкани и органи).</li><li><strong>Транстубарен път:</strong> Транспортиране на ракови партикули през маточните тръби до <strong>яйчника</strong> и коремната кухина с последващо имплантиране.</li><li><strong>Лимфогенен път:</strong> Метастази в регионалните и отдалечените лимфни възли.</li><li><strong>Хематогенен път (късен):</strong> Метастази в белите дробове, черния дроб и надбъбреците.</li></ol><p><strong>Прогностични фактори:</strong></p><ul><li><strong>Степен на диференциация</strong> (Grading);</li><li><strong>Дълбочина на инвазията</strong> в миометриума;</li><li><strong>Клиничен стадий</strong>.</li></ul><p><strong>Статистика:</strong> 5-годишната преживяемост е до <strong>90%</strong>, при условие че ракът не достига маточната шийка и инвазията в миометриума е под 1/3. Карциномите, свързани с естрогенно стимулиране, имат по-добра прогноза.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Лейомиом на матката</h2><p>Лейомиомът е най-честият доброкачествен тумор на матката, засягащ около една трета от жените над 30-годишна възраст. Туморът е <strong>естроген-зависим</strong>, поради което се развива в репродуктивна възраст и регресира след настъпване на менопаузата.</p><h3>Клиника</h3><p>Повечето миоми протичат <strong>безсимптомно </strong>и се <strong>откриват случайно </strong>при профилактичен преглед. Когато е налична симптоматика, тя зависи от локализацията, размера и броя на миомите. Най-честите признаци са тежест и/или болки в тазовата област, както и неправилни маточни кръвотечения. При вторична инфекция може да има треска, левкоцитоза и ускорена утайка.</p><h3><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-19/text-editor-images/2026/04/1776600231952-image.png &quot;width=100%&quot;)\" id=\"note-1776600233138-29\">Макроскопска характеристика</span></h3><p>Според локализацията си миомите биват:</p><ul><li><strong>Субмукозни:</strong> Под лигавицата.</li><li><strong>Интрамурални:</strong> В дебелината на маточната стена.</li><li><strong>Субсерозни:</strong> Под серозната обвивка, понякога на краче.</li></ul><p>По размер са от едва видими до 30 и повече cm, рядко са единични, а по-често множествени (до повече от 200) - <strong>миоматозна матка</strong>. \nТуморите са плътни, белезникави, с характерен <strong>завихрен строеж</strong>. Често настъпват вторични промени като оток, хиалинизация, некрози с образуване на кисти и калцификация.</p><h3><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-19/text-editor-images/2026/04/1776600247401-image.png &quot;width=100%&quot;)\" id=\"note-1776600248657-30\">Микроскопска характеристика</span></h3><p>Хистологичната картина показва преплитащи се снопчета от еднакви по размер <strong>вретеновидни гладкомускулни клетки</strong>. Клетките имат обилна еозинофилна цитоплазма и удължени ядра с тъпи краища. Туморът е богат на капиляри, а при наличие на по-дебелостенни съдове от артериален тип се говори за <strong>васкуларна миома</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Лейомиосарком</h2><p>Лейомиосаркомът е злокачествен тумор, съставляващ около 25% от саркомите на матката. Той засяга жени на средна възраст около 52 години и често се проявява с <strong>бързо нарастване на матката</strong> след менопаузата.</p><h3>Макроскопски</h3><p>Обикновено се представя като <strong>единичен интрамурален възел</strong> с мековата консистенция и сивкаво-розов цвят. Границите му са неясни и често се наблюдават обширни зони на некроза и кръвоизливи. </p><h3><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-19/text-editor-images/2026/04/1776608447953-image.png &quot;width=100%&quot;)\" id=\"note-1776600272362-31\">Микроскопски</span></h3><p>Установяват се снопчета от вретеновидни клетки с обилна еозинофилна цитоплазма. Ядрата са със заоблени краища и проминиращи нуклеоли. Има изразен <strong>клетъчен и ядрен полиморфизъм</strong> и <strong>гигантски многоядрени клетки </strong>от всички известни типове.</p><h3>Прогноза</h3><p>Лоша, като петгодишната преживяемост е под 20%.</p><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><br><br><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center; transition: background-color 0.3s\">Тема 98. Нетуморни кисти на яйчника. Ендометриоза.&nbsp;</h1><h2 style=\"text-align: left\">Нетуморни кисти на яйчника</h2><h3 style=\"text-align: left\">Инклузионни кистички</h3><p>Тези образувания представляват малки кухини, разположени в кортикалния слой на яйчника, които имат съществена роля в по-нататъшната онкогенеза.</p><p><strong>Механизъм на образуване\n</strong>Възникването им е пряк резултат от физиологичния процес на <strong>овулация</strong>. При всяко спукване на фоликул се нарушава целостта на покривния епител на яйчника, който представлява модифициран мезотел. По време на този процес <strong>единични мезотелни клетки</strong> могат да попаднат във вътрешността на яйчниковата кора, където се затварят и оформят малки кистични пространства.</p><p><strong>Клинично и патогенетично значение\n</strong>Макар самите инклузионни кистички да са доброкачествени и нетуморни по своята същност, те се считат за основен източник, от който се развиват <strong>епителните яйчникови тумори</strong>. Това е възможно благодарение на способността на примитивния епител да се диференцира в различни тъканни типове (серозни, муцинозни или ендометриоидни) дори когато е разположен в дълбочината на органа.</p><h3>Ендометриозни (шоколадови) кисти</h3><p>Ендометриозата е нетуморно заболяване, което често води до образуването на големи кистични формации в яйчниците на жени в активна репродуктивна възраст.</p><p><strong><span class=\"editor-note\" data-note=\"![Image](https://media.discordapp.net/attachments/1178611691076997130/1495423851319005316/image.png?ex=69e6317d&amp;is=69e4dffd&amp;hm=24f7b3cefce2865ac4285f80d16cf2c18bbc161edd64ad0a43de65b0304a3777&amp;animated=true&amp;width=1785&amp;height=1345 &quot;width=100%&quot;)\" id=\"note-1776600500478-32\">Макроскопска характеристика\n</span></strong>В началните си стадии ендометриозните огнища изглеждат като множество дребни кистички с червен, син или кафяв цвят. С течение на времето те могат да нарастват прогресивно и да достигнат значителни размери от <strong>над 15 сантиметра</strong>. Тези кисти се отличават с <strong>дебела фиброзна стена</strong> и вътрешна повърхност, която може да бъде гладка или леко гранулирана.</p><p><strong>Специфично съдържание\n</strong>Най-характерният морфологичен белег на тези кисти е тяхното съдържимо. Те са изпълнени с полутечна или кашеста <strong>кафеникава материя</strong>, която по цвят и консистенция наподобява течен шоколад. Този специфичен вид се дължи на разпада на кръвта, която се отделя в огнищата по време на всеки менструален цикъл. Поради тази особеност те са известни в клиничната патология като <strong>шоколадови кисти</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2 style=\"text-align: left\">Ендометриоза</h2><h3>Същност</h3><p><strong>Ендометриозата</strong> представлява патологично състояние, при което се установява наличие на <strong>ендометриални жлези и строма</strong> на ектопично място извън пределите на нормалната маточна лигавица. В случаите, когато процесът засяга миометриума, се използва терминът <strong>аденомиоза</strong>.</p><h3>Честота</h3><p>Това е често срещано заболяване, засягащо предимно жени в <strong>репродуктивна възраст</strong> (между 25 и 40 години). Истинската честота на заболяването е трудна за установяване, тъй като значителна част от пациентките нямат изявена клинична симптоматика.</p><h3>Етиология и морфогенеза</h3><p>Макар етиологията да не е напълно изяснена, се приемат две основни теории, които могат да се съчетават помежду си:</p><ol><li><strong>Метастатична ендометриоза:</strong> Базира се на механичното пренасяне и имплантиране на ендометриална тъкан чрез няколко пътя:</li><ul><li><strong>Менструална имплантация:</strong> Свързва се с <strong>ретроградна менструация</strong>, при която късчета ендометриум преминават през маточните тръби и се развиват по перитонеума.</li><li><strong>Интраоперативна имплантация:</strong> Възниква в оперативни разрези след коремни хирургични интервенции.</li><li><strong>Лимфно и кръвоносно разпространение:</strong> Обяснява наличието на ендометриозни огнища в отдалечени органи като белите дробове или скелетната мускулатура.</li></ul><li><strong>Метапластична ендометриоза:</strong> Основава се на хипотезата, че перитонеалният мезотел и мезенхимът могат да се диференцират в структури, идентични с ендометриума, поради общия им ембрионален произход. Тази теория обяснява наличието на заболяването при пациенти със синдром на Търнър и гонадална дисгенезия, както и редките случаи при мъже.</li></ol><p>Допълнителни фактори в етиологията са <strong>генетичната предиспозиция</strong> и <strong>хормоналните влияния</strong>, свързани с високо ниво на <strong>естрогени</strong>.</p><h3><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-19/text-editor-images/2026/04/1776600530436-image.png &quot;width=100%&quot;)\" id=\"note-1776600531479-33\">Локализация</span></h3><p>Ендометриозата се локализира най-често в <strong>яйчниците</strong>, <strong>маточните връзки </strong>и <strong>тазовия перитонеум</strong>. По-рядко може да се срещне в маточната шийка, влагалището, апендикса, пикочния мехур и тазовите лимфни възли. В изключително редки случаи се описва в белия дроб и червата.</p><h3>Макроскопска характеристика</h3><p>Ендометриозните огнища са множествени и се представят като <strong>дребни кистички</strong> с червен, син или кафяв цвят. С течение на времето размерите им могат да нараснат значително, като в яйчниците достигат диаметър от 15 и повече cm. Тези формации имат дебела фиброзна стена и съдържат гъста, кашеста кафеникава материя, наподобяваща течен шоколад, поради което се наричат <strong>шоколадови кисти</strong>.</p><h3>Микроскопска характеристика&nbsp;</h3><p>Микроскопски се установява наличието на <strong>ектопичен ендометриум</strong>, изграден от три основни компонента: </p><ul><li><strong>Ендометриални жлези</strong>.</li><li><strong>Ендометриална строма</strong>.</li><li><strong>Сидерофаги </strong>(наличието на сидерофаги е ключов диагностичен белег за хронични кръвоизливи в огнищата).</li></ul><p>В около 80% от случаите тази тъкан притежава <strong>хормонална рецептивност </strong>и търпи циклични изменения, синхронни с тези на нормалната маточна лигавица. В периода на менопаузата или при специфично лечение структурите обикновено атрофират и се заместват от фиброзна съединителна тъкан.</p><h3>Клиника</h3><p><strong>Основните клинични симптоми</strong> при локализация по яйчниците и тазовия перитонеум са:</p><ul><li><strong>Дизменорея</strong> и хронична болка.</li><li><strong>Нерегулярни маточни кръвотечения</strong>.</li><li><strong>Стерилитет</strong>.</li></ul><h3>Диагноза</h3><p>В класическото си представяне ендометриозата не създава диагностични затруднения поради типичната морфологична картина - ендометриум на ектопично място.</p><h3>Прогноза</h3>На основата на ендометриоза, макар и рядко, могат да се развият тумори, които по строеж са идентични с тези, произлизащи от ендометриума на маточното тяло.<span style=\"color: rgb(88, 129, 87); font-weight: 600\"><br><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><br><br></span><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center; transition: background-color 0.3s\">Тема 99. Тумори на яйчниците.&nbsp;Класификация, морфологична характеристика.</h1><h2>Класификация</h2><p>Яйчникът е органът с най-голямо разнообразие на тумори в човешкото тяло, което създава затруднения в терминологията. Класификацията се основава на <strong>хистогенетичния принцип</strong>:</p><ol><li><strong>Епителни</strong></li><li><strong>Тумори от половите върви (sex cord tumours)</strong></li><li><strong>Герминативноклетъчни</strong></li><li><strong>Неспецифични за яйчника тумори</strong></li><li><strong>Некласифицирани тумори</strong></li><li><strong>Метастатични</strong></li></ol><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>ЕПИТЕЛНИ ТУМОРИ</h2><p>Представляват 2/3 от всички яйчникови неоплазми и <strong>90% от карциномите</strong>. Произхождат от повърхностния епител (модифициран мезотел) и инклузионните кистички в дълбочина.</p><h4>Серозни тумори</h4><p>Епителът им наподобява този в маточната тръба. Биват бенигнени, с гранична малигненост и малигнени.</p><ul><li><strong>Макроскопия:</strong> Биват кистични, папиларно-кистични, само папиларни, солидни или солиднокистични.</li><ul><li><strong>Бенигнени цистаденоми:</strong> Обикновено еднокамерни, тънкостенни, с гладка повърхност и бистра сламеножълтеникава течност. Могат да достигнат над 30 см. Папилите (ако има) са плътни и ниски. Могат да са на краче (риск от торзия) или да руптурират (остър корем).</li><li><strong>Малигнени:</strong> Често двустранни и солиднокистични. Кухината е изпълнена с меки и късливи папили. Солидната част е мозъковидна с некрози и кръвоизливи.</li></ul><li><strong>Микроскопия:</strong> В стромата често се откриват <strong>псамомни телца</strong> (калцификати), хемосидерофаги и оток. Характерна е тясна безклетъчна ивица между епитела и стромата на папилите.</li><li><strong>Тъмори с гранична малигненост:</strong> Клетките са морфологично ракови, но категорично <strong>липсва инвазия в стромата</strong> и ангиогенни метастази. Прогнозата е по-благоприятна.</li></ul><h4>Муцинозни тумори</h4><ul><li><strong>Макроскопия:</strong> Доброкачествените са обикновено едностранни, <strong>многокамерни кисти</strong>, достигащи огромни размери. Стената е плътна, повърхността – гладка, а съдържимото – гъста слуз. Нямат папили. Муцинозният карцином съдържа меки папили и солидна тъкан.</li><li><strong>Микроскопия:</strong> Клетките са високи цилиндрични със светла, изпълнена със слуз цитоплазма и базални ядра. При карциномите слузната продукция намалява и се появяват жлези \"гръб до гръб\".</li><li><strong>Pseudomyxoma peritonei:</strong> Имплантиране на слузпродуциращи клетки по перитонеума след руптура на киста.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>SEX CORD (ПОЛОВИ ВЪРВИ) - СТРОМАЛНИ ТУМОРИ</h2><h3>Определение, терминология и морфогенеза</h3><p>В тази група се включват тумори, чийто паренхим произлиза от гонадната строма и съдържа:</p><ul><li>Гранулозни клетки;</li><li>Тека клетки и техни лутеинизирани производни;</li><li>Sertoli клетки;</li><li>Клетки на Leydig;</li><li>Фибробласти.</li></ul><p>Туморът може да е изграден от един от изброените клетъчни видове или от няколко — в различни комбинации и степени на диференциация.</p><h3>Ендокринна активност и биосинтеза</h3><p>Много от туморите в тази група са функционално активни и продуцират полови стероиди. Общ изходен субстрат за стероидогенезата — както в тестисите, така и в яйчниците — е холестеролът.</p><p>Синтезът на естрогените протича чрез междинно образуване на андрогени. Поради това, при тумори с преобладаваща естрогенна продукция могат да се наблюдават и андрогенни ефекти (вирилизация), както и обратното.</p><p>Тази особеност на стероидната биосинтеза обуславя възможността един и същ хистологичен тип тумор да продуцира различни полови стероиди в зависимост от степента и посоката на диференциация на туморните клетки.</p><h3>Гранулозо-стромален тумор (тип на възрастните)</h3><ul><li><strong>Честота:</strong> Около 2% от яйчниковите тумори и 95% от гранулозоклетъчните. Най-честият естроген-продуциращ тумор.</li><li><strong>Разпространение:</strong> Среща се главно при жени около и след менопаузата (пик 50-55 г.).</li><li><strong>Клиника:</strong> Придружава се от ендометриална хиперплазия или рак на маточното тяло. Рядко продуцира андрогени (вирилизация). В 10% настъпва руптура с хемоперитонеум.</li><li><strong>Макроскопия:</strong> Размери от микроскопски до 16 kg. Солиден, белезникаво-сив с жълтеникав оттенък, понякога с некрози, кръвоизливи и кисти.</li><li><strong>Микроскопия:</strong> Много разнообразна картина. Класически е <strong>микрофоликуларният вариант</strong> с <strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-19/text-editor-images/2026/04/1776625295641-image.png &quot;width=100%&quot;)\" id=\"note-1776625297709-0\">телца на Call-Exner</span></strong> (кухинки с еозинофилна течност и ядрени отломки, оградени от клетки с бледи ядра с надлъжен гребен).</li><li><strong>Прогноза:</strong> Непредвидима. Не метастазира, но рецидивира късно (след 10-20 г.).&nbsp;</li><li><strong>Рискови фактори:</strong> Възраст над 40 г., солидна структура, размер над 15 cm, атипизъм и висок митотичен индекс.</li></ul><h3>Теком</h3><ul><li><strong>Честота:</strong> Обикновено у жени над 50 години.</li><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-19/text-editor-images/2026/04/1776625326574-image.png &quot;width=100%&quot;)\" id=\"note-1776625332331-1\">Макроскопия</span>:</strong> Солидна, окръглена неоплазма (5-10 cm), плътна, с жълтеникави зони на среза.</li><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-19/text-editor-images/2026/04/1776625366795-image.png &quot;width=100%&quot;)\" id=\"note-1776625378428-2\">Микроскопия</span>:</strong> Клетки, подредени в преплетени снопчета, сочни, <strong>овални</strong>, подобни на фибробласти. Цитоплазмата е вакуолизирана и често съдържа <strong>липиди</strong>. Ядрата са без атипизъм.</li><li><strong>Функция:</strong> Най-често продуцират естрогени (хиперплазия/рак на ендометриума), рядко андрогени.</li><li><strong>Прогноза:</strong> Почти без изключение са бенигнени.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>ГЕРМИНАТИВНОКЛЕТЪЧНИ ТУМОРИ</h2><h3>Морфогенеза</h3><p>Тези тумори се развиват от <strong>примитивните герминативни клетки</strong> (общи за двата пола), които са от ендодермален произход. В ембрионалното развитие те се появяват в стената на жълтъчния мехур и мигрират през бъдещата коремна и гръдна кухина до епифизата, след което достигат до гонадния хълм и навлизат в паренхима на бъдещите гонади.</p><p>Тези факти обясняват две обстоятелства:</p><ol><li>Характерните герминативноклетъчни тумори се срещат и при двата пола.</li><li>Те се срещат аксиално или парааксиално по пътя на миграция (пинеална област, преден медиастинум, ретроперитонеално и сакрококцигеално).</li></ol><p>Омнипотентната герминативна клетка има два пътя на развитие:</p><ul><li><strong>Нормално:</strong> в ембрион и околоплодни обвивки.</li><li><strong>Туморно:</strong> в недиференцирани, с ембрионална или с екстраембрионална диференциация неоплазми.</li></ul><p>Потентността на тези клетки обяснява голямото разнообразие на структури (от трите зародишеви листа), които могат да се открият в тях.</p><h3>Класификация (СЗО)</h3><ol><li><strong>Dysgerminoma</strong></li><li><strong>Endodermal sinus tumour</strong></li><li><strong>Ембрионален рак</strong></li><li><strong>Polyembryoma</strong></li><li><strong>Choriocarcinoma</strong></li><li><strong>Тератоми:</strong> незрели; зрели; монодермални (struma ovarii, carcinoid и др.).</li></ol><h3>Dysgerminoma (Seminoma ovarii)</h3><ul><li><strong>Честота:</strong> 1-3% от яйчниковите тумори. 80% от случаите са при млади жени (15–30 г.).</li><li><strong>Клиника:</strong> Тежест или болки в тазовата област. Остри болки при торзия или руптура. Често се открива по време на бременност.</li><li><strong>Макроскопия:</strong> В 15-20% е двустранен. Солиден, окръглен, лобулиран, с оформена капсула (средно 15 cm). На срез е мозъковидно мек, сивкаво-розов или жълтеникав.</li><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-19/text-editor-images/2026/04/1776625564518-image.png &quot;width=100%&quot;)\" id=\"note-1776625565856-3\">Микроскопия</span>:</strong> Повлекла и островчета от големи, еднакви полигонални клетки със светла цитоплазма. Ядрата са везикуларни с няколко нуклеоли. <strong>Характерна е обилна лимфоцитна инфилтрация в стромата.</strong> Могат да се открият елементи и от други герминативни тумори.</li><li><strong>Прогноза:</strong> Разпространява се чрез директно прорастване и по лимфен път (парааортални, медиастинални лимфни възли). Макар и лъчечувствителен, прогнозата е лоша (5-годишно оцеляване 28%).</li></ul><h3>Ендодермален синусов тумор (Yolk sac tumour)</h3><p>Изключително малигнен тумор, изграден от ендодермални елементи на жълтъчния мехур и екстраембрионален мезобласт.</p><ul><li><strong>Честота:</strong> Среща се в млада възраст (5–20 г.). Бърз растеж (2-3 месеца).</li><li><strong>Клиника:</strong> Резки коремни болки (руптури). В серума се откриват високи нива на <strong>алфа-фетопротеин (AFP)</strong>.</li><li><strong>Макроскопия:</strong> Голям (до 5 kg), сфероиден, сивкаво-розов на срез с кистички, съдържащи желатинозно съдържимо.</li><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-19/text-editor-images/2026/04/1776625678375-image.png &quot;width=100%&quot;)\" id=\"note-1776625680224-4\">Микроскопия</span>:</strong> Много разнообразна. Характерни са <strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-19/text-editor-images/2026/04/1776625736561-image.png &quot;width=100%&quot;)\" id=\"note-1776625737681-5\">телцата на Schiller-Duval</span></strong> (централен капиляр, обграден от ембрионални клетки). Наблюдават се PAS+ хиалинни глобули (алфа-фетопротеин).</li><li><strong>Прогноза:</strong> Екстремно малигнен; рано прораства и метастазира (бял дроб, черен дроб). Фатален изход до 2 години. <strong>Не е лъчечувствителен!</strong></li></ul><h3>Тератоми</h3><p>Произлизат от партеногенеза на примитивната герминативна клетка.</p><h4>Незрели тератоми (Teratoma embryonale)</h4><ul><li><strong>Честота:</strong> 1% от всички тератоми. Срещат се в първите две десетилетия.</li><li><strong>Макроскопия:</strong> Обикновено едностранни, големи (до 30 cm), солидни с кисти. Срезната повърхност е пъстра (сиво до тъмнокафяво).</li><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-19/text-editor-images/2026/04/1776625768524-image.png &quot;width=100%&quot;)\" id=\"note-1776625769820-6\">Микроскопия</span>:</strong> Незрели тъкани от трите листа: ектодерма (нервна тъкан), мезодерма (хрущял, кост, мускули), ендодерма (цилиндричен епител).</li><li><strong>Прогноза:</strong> Неблагоприятна (5-годишно оцеляване &lt; 20%). Бързо разпространение по перитонеума.</li></ul><h4>Зрял кистичен тератом (Дермоидна киста)</h4><ul><li><strong>Честота:</strong> 10-20% от всички яйчникови тумори. Репродуктивна възраст.</li><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-19/text-editor-images/2026/04/1776625813490-image.png &quot;width=100%&quot;)\" id=\"note-1776625814521-7\">Макроскопия</span>:</strong> Сфероидна киста с плътна капсула. Съдържа течна мазнина, която застива при стайна температура, и <strong>косми</strong>. Често има зъби (30%), хрущял или кост.</li><li><strong>Микроскопия:</strong> Вътрешната повърхност е кожа с придатъци. Доказват се екто- (100%), мезо- (90%) и ендодермални (70%) структури.</li><li><strong>Прогноза:</strong> Благоприятна. Усложнения: торзия, руптура, инфекция или малигнизация (обикновено плоскоклетъчен рак).</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>МЕЗЕНХИМНИ ТУМОРИ, НЕСПЕЦИФИЧНИ ЗА ЯЙЧНИКА</h2><h3>Фибром</h3><ul><li><strong>Честота и разпространение:</strong> Съставлява 3-5% от всички яйчникови тумори. Среща се обикновено у по-възрастни жени (средна възраст 48 години).</li><li><strong>Морфогенеза:</strong> Произхожда от мезенхимни клетки на яйчниковата строма, диференцирани като фибробласти. Поради този произход често се класифицира в групата на <em>sex cord</em> – стромалните тумори.</li><li><strong>Клиника:</strong> </li><ul><li>Най-често е безсимптомен поради малките си размери.</li><li>При по-големи размери се проявява като абдоминална маса или остра болка (при торзия).</li><li><strong>Асцит:</strong> Наблюдава се в 50% от случаите при тумори над 5 cm.</li><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-19/text-editor-images/2026/04/1776625934948-image.png &quot;width=100%&quot;)\" id=\"note-1776625936053-9\">Синдром на Meigs</span>:</strong> Класическа триада от яйчников фибром, асцит и хидроторакс (среща се в 2-3%). Изливите изчезват след отстраняване на неоплазмата.</li></ul><li><strong>Макроскопия:</strong> Размери от 1-2 cm до 13 kg. Туморът е сиво-бял, плътен (консистенция на сухожилие). На срез се виждат снопчета, завихряния, понякога некрози или малки кисти.</li><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-19/text-editor-images/2026/04/1776625890624-image.png &quot;width=100%&quot;)\" id=\"note-1776625891937-8\">Микроскопия</span>:</strong> Картина на типичен фибром с обилен междуклетъчен колаген.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>МЕТАСТАТИЧНИ ТУМОРИ НА ЯЙЧНИКА (ТУМОР НА KRUKENBERG)</h2><p>Този раздел разглежда метастази от екстрагенитални органи, най-често от <strong>стомашно-чревния тракт</strong> (стомах, дебело черво) и <strong>гърдата</strong>.</p><ul><li><strong>Честота:</strong> Около 6-7% от всички овариални неоплазми. Средната възраст е сравнително млада (45 години) поради по-богатата васкуларизация на яйчниците в репродуктивна възраст.</li><li><strong>Клиника:</strong> </li><ul><li>Нехарактерни симптоми: коремни болки и подуване.</li><li>Рядко: неправилни маточни кръвотечения или вирилизация (поради хормонопродукция от стимулираната строма).</li></ul><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-19/text-editor-images/2026/04/1776626076595-image.png &quot;width=100%&quot;)\" id=\"note-1776626077724-11\">Макроскопия</span>:</strong> Обикновено са <strong>двустранни</strong>, големи, бъбрековидни или сфероидни. Повърхността е хълмиста, а консистенцията – плътна до жилава.</li><li><strong><span class=\"editor-note\" data-note=\"PAS - Муцинът в клетките тип „пръстен с камък“ се оцветява в червено-виолетово.\n![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-19/text-editor-images/2026/04/1776626005683-image.png &quot;width=100%&quot;)\" id=\"note-1776626006767-10\">Микроскопия</span>:</strong> </li><ul><li>Наличие на единични клетки или малки групи клетки тип <strong>„пръстен с камък“</strong> (signet-ring cells) – изпълнени със слуз, която изтласква ядрото в периферията.</li><li>Стромата често е с изразена дезмопластична реакция.</li><li><strong>Диагностика:</strong> Използва се <strong>PAS-реакция</strong> за визуализиране на мукополизахаридите в цитоплазмата на клетките.</li></ul><li><strong>Прогноза:</strong> Изключително <strong>лоша</strong>. Средната преживяемост след поставяне на диагнозата е едва <strong>7 месеца</strong>.</li></ul><hr data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><br></p><p><br></p><hr data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center\">Тема 100. Възпалителни заболявания на млечната жлеза. Фиброкистична болест.</h1><h2>Възпалителни заболявания на гърдата (Мастити)</h2><p>Възпалителните заболявания на млечната жлеза, известни като <strong>мастит</strong>, се разделят на остри и хронични форми в зависимост от причинителя и морфологичната картина.</p><h3>Остър мастит</h3><p>Развива се най-често при млади жени в първите седмици на <strong>лактацията</strong>. Инфекцията прониква през рагади на зърното, като най-чест причинител е <strong><i>Staphylococcus aureus</i></strong>, по-рядко стрептококи.</p><ul><li><strong>Макроскопски:</strong> Млечната жлеза е <p>увеличена, напрегната, зачервена и силно болезнена.</p></li><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-19/text-editor-images/2026/04/1776626190778-image.png &quot;width=100%&quot;)\" id=\"note-1776626192253-12\">Микроскопски</span>:</strong>&nbsp;При стафилококова инфекция се наблюдават <strong>фокални огнища на остро възпаление</strong> с изразена <strong>неутрофилна инфилтрация</strong>, които имат тенденция към формиране на <strong>абсцеси</strong>. Стрептококовите мастити протичат по-тежко с картина на дифузно <strong>флегмонозно възпаление</strong>.</li><li><strong>Прогноза:</strong> <p>Обикновено благоприятна при своевременно лечение. При обширни некрози може да се развие фиброза с ретракция на кожата, имитираща карцином.</p></li></ul><h3>Хроничен мастит</h3><p>Тази група включва разнородни възпалителни процеси, които често налагат диференциална диагноза със злокачествени тумори.</p><h4>Основни варианти на хроничния мастит</h4><ul><li><strong>Перидуктален мастит:</strong>&nbsp;<p>Свързан е с <strong>тютюнопушенето</strong>. Характеризира се с <strong>плоскоклетъчна метаплазия </strong>на лактиферните канали и хронично, често грануломатозно възпаление. Склонен е към рецидиви и може да доведе до образуване на фистули.</p></li><li><strong>Дуктална ектазия:</strong>&nbsp;<p>Среща се предимно при многораждали жени в 5–6-то десетилетие. Наблюдава се дилатация на каналите, изпълнени с аморфен материал, съпроводена от перидуктална фиброза и хроничен възпалителен инфилтрат (лимфоцити, хистиоцити и плазмоцити).</p></li><li><strong>Мастна некроза (Липогранулом):</strong>&nbsp;<p>Най-често след травма или хирургична интервенция. Характеризира се с <strong>централна некроза</strong>, заобиколена от <strong>пенести макрофаги </strong>и <strong>гигантски клетки тип </strong>„<strong>чуждо тяло</strong>“, а в по-късните стадии — с <strong>калцификати</strong>.</p></li><li><strong>Грануломатозен лобуларен мастит:</strong>&nbsp;<p>Представя се като добре ограничена плътна формация. Микроскопски се установяват епителиоидноклетъчни грануломи с гигантски клетки тип Лангханс, локализирани в и около лобулите.</p></li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2><span class=\"editor-note\" data-note=\"![Image](https://images.openai.com/static-rsc-4/rdRlwii4misjNM-7KB6ZKpm8AP94chkzwy-43Jb0Hvb3FYIz-6vC5AjfgBFjefwPwtyu69qISRf7HgMPawf6DhUN-3k1Ld6NMBzbdEtHNISgOD4w4eiAf4AqrUdsVQcb888lj42lZ4KXLizp56noQpLHhZ9FfpW3Rvj1TONZhP5jjuR0bgwd9EXATyhc6Ifr?purpose=fullsize &quot;width=100%&quot;)\" id=\"note-1775382340785-5\">Фиброкистична болест</span> (Мамарна дисплазия, Мастопатия)</h2><p>Фиброкистичната болест е доброкачествено <strong>тумороподобно заболяване</strong>, което е най-честата диагноза в биопсичния материал от гърда. Засяга основно жени между 40 и 50 години, като честотата му намалява след менопаузата.</p><h3>Етиология</h3><p>Основна роля за развитието на заболяването играе <strong>хормоналният дисбаланс</strong>, изразяващ се в абсолютен или релативен <strong>излишък на естрогени</strong>. </p><h3>Макроскопски</h3><p>Макроскопски се откриват солитарни или множествени кисти с различна големина (от съвсем малки до 5-6 cm). Процесът се характеризира с комбинация от пролиферативни и регресивни промени, включващи епителните и съединителнотъканните елементи на жлезата.</p><h3>Микроскопски</h3><p>Картината се представя с четири основни вида изменения:</p><ol><li><strong>Кистични промени:</strong> Микрокисти и сляпо завършващи канали, в които често се наблюдава <strong><span class=\"editor-note\" data-note=\"**Основни морфологични белези:**\n- Големи клетки\n- По-едри от нормалния дуктален епител.\n- Обилен еозинофилен (розов) цитоплазъм\n- Цитоплазмата е гранулирана и силно оцветена → типичен белег.\n**Ядра**\n- Кръгли до овални\n- Често централно разположени\n- Могат да имат видими нуклеоли\n**Апикални “snouts” (изпъквания) **\n- Това е много характерно — върхът на клетката изглежда като „отщипан“.\n![Image](https://images.openai.com/static-rsc-4/r8ZM0JP2NJ482wH1bzePGtxs_-Jd4ASzOKOrXxyISV27fS9bPa9fZun5rOxm93ptOMptaEw0lfES6OgdR98lPu7ja6FYzvqCqx6QtjdN_kGXknrSxRi55e3PJfo1OyoDOXqgnjt-2BKgK7cEQRtZpAqSNbS3vJChMjxM4GVfj6EM8tnKCiPfr3pWJC2LBVYm?purpose=fullsize &quot;width=80%&quot;)\" id=\"note-1775381984528-0\">апокринна метаплазия</span></strong> на епитела.</li><li><strong>Фиброза:</strong> Разрастване на интралобуларната и перидукталната съединителна тъкан.</li><li><strong><span class=\"editor-note\" data-note=\"![Image](https://images.openai.com/static-rsc-4/GKPpweTXn64dXC0nxrAULn5qs-fHP4XpxwaV67hJMemsQByirXzDWAV66y6o5h7GHk0Yh2EDIQWAguGylQY19iU2YZaiflI_yNfgEDG7wX2G4olNQvgP3e-FIRSgQ-RF-c6icV51YlRuJvTt_RsovcEktLtEACmRNZrb7R3C1PWoEkuA46kSPSiE0ahk_ITy?purpose=fullsize &quot;width=20%&quot;)\" id=\"note-1775382314393-4\">Аденоза</span>:</strong> Увеличаване на броя на жлезните елементи в лобулите.</li><li><strong>Епителна хиперплазия (Епителиоза):</strong> Увеличаване на броя на епителните клетки в жлезните структури, започващо обикновено от терминалните канали.</li></ol><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Хиперпластични епителни лезии</h2><p>Епителните пролиферации се разделят според тяхната локализация и степен на атипизъм. Повечето лезии възникват от <strong><span class=\"editor-note\" data-note=\"ТДЛЕ е най-малката функционална и морфологична единица на млечната жлеза, съставена от терминален канал (ductulus) и свързаните с него лобули (ацинуси).\n![Image](https://images.openai.com/static-rsc-4/foo31yPMqrPnuHL-kbWDsg4S-xzC-lNsfo0XK5aS20YQOZfiAfQxYYQ11lwKCmBGEJJzODG5vBpbfGIlQQvVAawu9vlfQQqNZejfnzr5EmQ-OXwNbU8UaK_wz4qBw4-7MYOJrcusHJ0gZo-oU7wMSWaN_4ES9bcbMbo19PCsHyM?purpose=inline &quot;width=100%&quot;)\" id=\"note-1775382058182-1\">терминалната дуктуло-лобуларна единица (ТДЛЕ)</span></strong>.</p><h3><span class=\"editor-note\" data-note=\"![Image](https://images.openai.com/static-rsc-4/TNa70e3_r_CTx3uL74jNbZIq3N_gD_zW28aXeySAl-Y0PnG_kt_XdYMK5AW2-quOmIsWNnpbDbmrFf8qCmiHm9iEBztr1I_QVexummcwRi7KW0f1O7BmKD0EkGN9zGsO6Gaw2MYW0cjucs0xNATRuI5byPxaiL3l5JhxZatUZWM?purpose=inline &quot;width=30%&quot;)\" id=\"note-1775382122915-2\">Дуктална хиперплазия</span></h3><p>Възниква в екстралобуларните канали. Пролифериращите клетки могат частично или напълно да изпълнят лумена. Клетките при обикновената форма са малки, с правилни ядра и липсващи митози. При <strong>атипичната дуктална хиперплазия</strong> се наблюдава изразен клетъчен атипизъм, което налага диференциална диагноза с неинвазивен карцином.</p><h3><span class=\"editor-note\" data-note=\"![Image](https://images.openai.com/static-rsc-4/DVGtbXDdlXliQQdTcqVo0kEnZ7XFcpqcADiS6o46Ok-pLhsXy0lY_ZJOlKSDmkOj0ew3UESUYpu5XXqFy6b8g-U46l9aYkDHELx0S6cI4kGuzeGZ2Psuz0xz6eydWXoVMsIx3mSS7nmaEATE3JRlIc328Zva76M3lHHc6Cffbnk?purpose=inline &quot;width=60%&quot;)\" id=\"note-1775382146781-3\">Лобуларна хиперплазия</span></h3><p>Характеризира се с пролиферация в интралобуларните каналчета. <strong>Атипичната лобуларна хиперплазия</strong> засяга само част от лобуларната единица и води до леко деформиране на лобула.</p><h3>Клинично значение</h3><p>Фиброкистичните промени без епителна хиперплазия не се съпровождат от повишен риск от рак. Въпреки това, атипичните форми на дуктална и лобуларна хиперплазия се класифицират като <strong>преканцерози</strong> и са свързани с повишен риск от развитие на карцином на млечната жлеза.</p><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><br><br><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center; transition: background-color 0.3s\">Тема 101. Доброкачествени и злокачествени тумори на млечната жлеза. Морфологична характеристика.</h1><h1 style=\"text-align: center\">Доброкачествени тумори на млечната жлеза</h1><p>Доброкачествените тумори на гърдата произлизат предимно от епителните елементи на каналите и ацините, както и от околната съединителна тъкан. Повечето от тях възникват от терминалната дуктуло-лобуларна единица (ТДЛЕ).</p><h2><span class=\"editor-note\" data-note=\"![Image](https://images.openai.com/static-rsc-4/FpQMdfFJ6v2nM8SUOk5i5eNoEqfqDTlMHsljdMel-SW1aCzcxfrzX7gh9cbCuAGQigvWgBP-NvW4iCiB941DNR4R8P7dpdHVNpMe9N4KK2ruAYMpFOnVp0QTrJBDrAMTy5KNlIsCqhe0S6fINoMnrKnYPrHgOjnDk1P5NAJF4Sor65opEEG1lykoJsLxw9mn?purpose=fullsize &quot;width=100%&quot;)\" id=\"note-1775382570758-6\">Интрадуктален папилом</span></h2><p>Това е сравнително рядък тумор, който се среща най-често при жени в 3-то и 4-то десетилетие. Локализира се предимно в <strong>големите субареоларни канали</strong>. В 70% от случаите основният клиничен симптом е наличието на <strong>кръвенист или серозен секрет от мамилата</strong>.</p><p>Микроскопски се наблюдават <strong>дървовидно разклонени пролиферации</strong>, които изхождат от една или няколко зони на дилатиран канал. Стволът на папилите е покрит с еднореден цилиндричен епител без атипизъм, под който се намира добре запазен <strong>миоепителен слой</strong>. Сливането на съседни папиларни разклонения често води до формиране на жлезоподобни пространства, тапицирани от епител и миоепителен слой. В папиломите често се откриват зони на <strong>апокринна метаплазия</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Аденоми</h2><p>Аденомите са добре ограничени тумори, изградени от жлезни елементи и вариращо количество строма. Описват се няколко основни форми:</p><ul><li><strong><span class=\"editor-note\" data-note=\"![Image](https://images.openai.com/static-rsc-4/oAy5YATT3eu3evHav3zND5-s2slb67FuHWPs0FPUjaiVH75qV3AizsGVUY3BDm5QuhCe24Dz64o_rTNMBKdTBvmhbfBHkm7XENshBwN6Pp7qmpwbL-fH_LxjY0oFSaepk03Jovl2ZqkhEvLhPKSI9vLXT3SQdqPsT-THllEUXEyAG4cLqAkN8guQRTAeE8Kg?purpose=fullsize &quot;width=100%&quot;)\" id=\"note-1775382629019-7\">Тубуларен аденом</span>:</strong> Изграден от правилни, еднакви по големина тубули с оскъдна строма между тях.</li><li><strong><span class=\"editor-note\" data-note=\"![Image](https://images.openai.com/static-rsc-4/EHBa7Rligh9o8FSvW7ZIg4mqs9pcbgGQ3_K22l0vseLtKmiDHh1a3WroHuUqcctXSq__6sqsk-0Kf6IK34PHzO_KSFO_DekNCVeYixMOHF78ON75dAhihtkUgbthUvxjSzdtqio-h34E5v88-79jmjnpy4b6PU3zLdkefWWjJDHn3TgZILjRb1i6GS-cSAl7?purpose=fullsize &quot;width=100%&quot;)\" id=\"note-1775382666068-8\">Лактиращ аденом</span>:</strong> Наблюдава се при бременни и кърмещи жени. Характеризира се с изразени <strong>секреторни промени</strong>, <strong>липидни вакуоли </strong>в цитоплазмата и <strong>секрет </strong>в <strong>лумените</strong>.</li><li><strong>Дуктален аденом:</strong> Представлява хиалинизирала фиброзна тъкан с пръснати малки дуктални елементи.</li><li><strong>Аденом на мамилата:</strong> Папиларна или солидна лезия, която се открива в лактиферните синуси&nbsp;<p>и е </p><p>изградена от интрадуктални пролиферации.</p></li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2><span class=\"editor-note\" data-note=\"![Image](https://images.openai.com/static-rsc-4/WS1vwOjsevHKkcuiYrYv3B3hZOmxvO0ujxt-tMFi0i0gCJgERRU0jwHFnly59qxtSFbwI3gTp-aSgoQUiNkPlTiAJOGKhkoEgmfS3wJ0SaZBJXwIeBgPmaKNnLRb-UYqEmsEs7XzVGiitXgvKZIwk8dmFXZUEvHBWj0aKjRQuiNjNKdTfGwW8r1xZH9pYjQy?purpose=fullsize &quot;width=100%&quot;)\" id=\"note-1775382944945-12\">Фиброаденом и филоиден тумо</span>р</h2><p>Тези два тумора принадлежат към групата на <strong>смесените мезенхимни/епителни тумори</strong>, тъй като включват пролиферация както на съединителнотъканния, така и на епителния компонент.</p><h3><span class=\"editor-note\" data-note=\"![Image](https://external-content.duckduckgo.com/iu/?u=https%3A%2F%2Fimage.slidesharecdn.com%2Fbreastcarcinomapathology-110914235857-phpapp01%2F95%2Fbreast-carcinoma-pathology-53-728.jpg%3Fcb%3D1316046069&amp;f=1&amp;nofb=1&amp;ipt=e43aa4f38c12d6e41d8b7340dcccca3d09a058b4aec100f79990cba2de448ae7 &quot;width=100%&quot;)\" id=\"note-1775382918813-11\">Фиброаденом</span></h3><p>Това е третият по честота тумор на гърдата, типичен за възрастта между <strong>20 и 45 години</strong>. \n<strong>Макроскопски </strong>е добре ограничен, плътен и лобулиран възел. \n<strong>Микроскопски </strong>се различават два класически варианта:</p><ul><li><strong><span class=\"editor-note\" data-note=\"![Image](https://images.openai.com/static-rsc-4/R_MW1pL5VpkBUMP4b20ew54BLjJ6iT6VhecjmY0kWZJzggEcPC6vn5xFSQdvD9XrjB_ND4CZU3HzffF0961M9mKHuu5cPIoECMz84x1jKCL-kSQetvbdwCEiQh-jUN5h22vPu4FormdmuOsukoHvXO9txbTrkqMd-cqfUQAWMGz0ZQB4yoUxP37OCfbLFpi7?purpose=fullsize &quot;width=100%&quot;)\" id=\"note-1775382908874-10\">Периканаликуларен</span>:</strong> Туморната строма обгражда жлезните структури, без да ги деформира.</li><li><strong><span class=\"editor-note\" data-note=\"![Image](https://images.openai.com/static-rsc-4/OJh75GqzVUKnjp803hJXHIBFxc7CD7h8wA9tRgX5PQc6oVPYcQn0GGyK1CcKBrie1bdvZTinyiivJ4l9mKDm9DPX13ZtLCml60f95kIp6ZWgtVKOXC9M8YNH6LALQOcwco07O1Cnn-ZlFbVUD7cfiUGnGPUNqYzCSBM9Kwtzt06IiEKPM8mfRn4IBvtth7DT?purpose=fullsize &quot;width=60%&quot;)\" id=\"note-1775382845774-9\">Интраканаликуларен</span>:</strong> Стромата пролиферира по такъв начин, че притиска каналите, превръщайки ги в тесни цепки.</li></ul><p>Специфична форма е <strong>ювенилният фиброаденом</strong>, който се среща при млади момичета и се отличава с изразена епителна хиперплазия.</p><h3><span class=\"editor-note\" data-note=\"![Image](https://images.openai.com/static-rsc-4/vfu86AjYXC8jE5u5ok_l8W3K8ulpPBP4xxQu1Zbh8RmXI8Uz9TT6HqD9gpYpLwwBum6xuyNs_DDj49Ls2kAm0VJayYkqUUjH2TwkInxTuVfFZahNticvoauZanGaD2p9Y-10bsKIRWxX3dRuMi0i66yHd7VQHl4zv-tl4CETjVwZtUQjjSnBY3WMVH4JA0U9?purpose=fullsize &quot;width=100%&quot;)\" id=\"note-1775382956700-13\">Филоиден тумор</span> (Цистосаркома филодес)</h3><p>Рядък тумор (под 0,5% от всички случаи), който наподобява фиброаденома, но се отличава с <strong>изразен стромален целуларитет</strong>. Името му произлиза от характерната <strong>листовидна структура</strong> (филоидна), която се вижда при макроскопски срез. В зависимост от броя на митозите и атипизма, се класифицира като доброкачествен, граничен или злокачествен. Злокачествените варианти метастазират предимно по хематогенен път.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center\">Злокачествени епителни тумори (Карциноми)</h1><h2>Неинвазивен (in situ) карцином</h2><p>Неинвазивните карциноми се срещат най-често в комбинация с инвазивен такъв (честота 1,4–5,3%). Различават се два главни типа:</p><h3><span class=\"editor-note\" data-note=\"![Image](https://images.openai.com/static-rsc-4/sT-o0vIc2WulDb2RdlT4hiNOShKglzvx0EXnVWqAaoZKPFm318sOTPqEzkYAZeg0WNrI7CDRHeaUTfyuMagnL9tNLfWlu7awliuTbZFMdN2Hwt-cLYAPx2G-fffhf9aUr6M9dSx2F1Sa5emWNtonqogcp27op9akCCqIdiC_zmPBx2PneD3OzT0XYVwq8wnW?purpose=fullsize &quot;width=100%&quot;)\" id=\"note-1775383369682-15\">Неинвазивен дуктален карцином</span></h3><p>Около 60% от неинвазивните карциноми. Средна възраст: 50–60 години.</p><ul><li><strong>Макроскопия:</strong> Солиден или папиларен строеж, размери от няколко мм до 5 см. Сиво-белезникав, трошлив; възможни некрози (\"жълтеникава материя\") и кръвоизливи.</li><li><strong>Микроскопия:</strong> Четири основни типа:</li><ol><li><strong>Солиден</strong></li><li><strong>Крибриформен</strong></li><li><strong>Микропапиларен</strong></li><li><strong></strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-19/text-editor-images/2026/04/1776608343897-image.png &quot;width=100%&quot;)\" id=\"note-1775383311463-14\"><strong>Комедо</strong> </span>(с централна некроза)</li></ol><li><strong>Особености:</strong> В 30% от случаите е мултицентричен в същата гърда. Диференциална диагноза се прави с дуктална хиперплазия.</li></ul><h3><span class=\"editor-note\" data-note=\"![Image](https://images.openai.com/static-rsc-4/NrUVrLjzA3XdmmbUpWkAATMyNLObUPb0NPwmaFIsAkDuThkSgrDeL7_k5x21tDoB6XfModZeTep9ygmMyc3MktOStxeDqmtdCJiKrfbq_sexlTfgS-DqmJlhynO0I6fqkRPLUQS3LafjiEAJcEeOxm6d0PZ1sm2zH4cF4dquu0sZ-WKqguilF4zn-sTmuAnP?purpose=fullsize &quot;width=100%&quot;)\" id=\"note-1775383397467-16\">Неинвазивен лобуларен карцином</span></h3><p>Съставлява 30% от неинвазивните карциноми.</p><ul><li><strong>Клинични данни:</strong> Често не се палпира като тумор и се открива случайно при операция по друг повод.</li><li><strong>Микроскопия:</strong> Характеризира се с изпълване на ацините на лобулите от мономорфни клетки. Често се наблюдават микрокалцификати.</li><li><strong>Особености:</strong> Висока <strong>мултицентричност </strong>и често <strong>двустранно </strong>засягане.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Инвазивен карцином на гърдата</h2><p>Инвазивните карциноми са хетерогенна група злокачествени тумори, които са пробили базалната мембрана и инфилтрират околната строма. Те се различават по своята честота, хистологичен строеж и прогноза.</p><h3><span class=\"editor-note\" data-note=\"![Image](https://images.openai.com/static-rsc-4/kLktaKUw58JAQnCVvJbKd4D2TeNYwBz-Zfxktk89Vr5Y5QEMRkzbSaoD4_FNUXDF-greJV5-hzxIqkqvlcpsouwMMZa_k_1rpqqnBrADxhMWGvRQzXdl4R3nArY7TYU5VFJweiAUv3y7XEIQ-UkhkKAYcEec1sd4Ya6SlS_DOBZYZPZjXO5XWyFS8khSrG4e?purpose=fullsize &quot;width=100%&quot;)\" id=\"note-1775383626218-19\">Инвазивен дуктален карцином</span></h3><p>Това е най-често срещаният хистологичен вариант на рак на гърдата (около 70-80% от случаите).</p><ul><li><strong>Макроскопия:</strong> Туморът обикновено е с неправилна, <strong>звездовидна форма</strong>, много плътен и със сиво-белезникава срезна повърхност.</li><li><strong><span class=\"editor-note\" data-note=\"![Image](https://images.openai.com/static-rsc-4/YypUyKm8P3f_v5HozyA18t0udRpt-aVcGPJcRTAhPyp2HbAy40nCSNw__6LKXBNign-r5cHfQ7pJgiacYdkzJMAQPLSM-FRKYdN3GEe4FYIenW5ApneOBDH_5JmZKJDCSq3X6E0UJ_O8RCQrUgSAyCO6O7iItNsYw8SPXW5PsXFthK3tzGAqcXPz3m30nyN3?purpose=fullsize &quot;width=100%&quot;)\" id=\"note-1775383635442-20\">Микроскопия</span>:</strong> Туморните клетки са подредени в групи, жлезни структури, трабекули или масивни повлекла. Клетките са <strong>полиморфни </strong>- големи, полигонални, с обилна цитоплазма и големи ядра с видими нуклеоли. <p>Стромата може да бъде оскъдна, равномерно разпределена или обилна, с участъци на хиалинизация.</p></li><li><strong>Вариант с преобладаващ интрадуктален компонент:</strong> Колкото по-голям е делът на неинвазивния компонент спрямо инвазивния, толкова по-ниска е честотата на лимфните метастази (по-добра прогноза), но се наблюдава по-висок риск от локални рецидиви при органосъхраняващи операции.</li></ul><h3><span class=\"editor-note\" data-note=\"![Image](https://images.openai.com/static-rsc-4/_4V2TR4H4ekya9gfbmPCb-s8fe_364xlo2lOzC6m_RUyypnFRLKMT-Jij2bWPQ1CS_SURp6nmph7iMjzBW5kEB5dLKkqQ9QFCRyY_MNOjnwtNPYBjfJjTMrjE3-8vMssfDucVvkVIfuHFR5x2g_ggPtYHSNb1ABnGmojwr_EIc_bWA_vxNIzoFxlH6uu3ZtV?purpose=fullsize &quot;width=100%&quot;)\" id=\"note-1775383820131-21\">Инвазивен лобуларен карцином</span></h3><p>Вторият по честота вариант (около 10-15%). Характеризира се със специфичен начин на инфилтрация.</p><ul><li><strong>Микроскопия:</strong> Изграден от <strong>мономорфни </strong>дребни клетки с бледа цитоплазма и малки хиперхромни ядра. Тези клетки често са „несвързани“.</li><li><strong>Характерни структури:</strong></li><ul><li><strong>\"<span class=\"editor-note\" data-note=\"![Image](https://images.openai.com/static-rsc-4/OY5HU8JEpNSgPfeC2BH5-Mk-UjQ35OFzBZfb2Sw4UGZtv0CIpq5mejGCq7CPgPEAVRBRIF5zLKT0wYowIYV5h-e6GIm-VXTmbvnY949JZbaTK9N3Nl_OJkDIq9uXVTrWPWU2Bqu1YFcsUgzUW3-pjpTfHVLr6cxu_pPqT3rt1aqqJ1XtgL32XHYXiZQHirVi?purpose=fullsize &quot;width=100%&quot;)\" id=\"note-1775383831488-22\">Индианска нишка</span>\"</strong>: подреждане на клетките в редици от по един ред.</li><li><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-18/text-editor-images/2026/04/1776512293284-image.png &quot;width=100%&quot;)\" id=\"note-1775383865764-23\">Таргетовидно подреждане</span>:</strong> клетките се подреждат концентрично около запазени нормални канали.</li></ul><li><strong><span class=\"editor-note\" data-note=\"| Вариант | Строеж | Клетъчен тип | Прогноза |\n|-----------------|--------------------------------------------|--------------------------------------|------------------------|\n| Класически | Редици от единични клетки | Малки, мономорфни клетки | Най-добра |\n| Солиден | Солидни повлекла или неправилни гнезда | Мономорфни клетки | Най-ниска преживяемост |\n| Алвеоларен | Окръглени агрегати (&gt;20 клетки) | Мономорфни клетки | Добра |\n| Плеоморфен | Редици от полиморфни клетки | Изразен полиморфизъм, митози | Неблагоприятна |\n| Тубулолобуларен | Тубули и редици от клетки | Мономорфни клетки | Много добра |\n![Image](https://images.openai.com/static-rsc-4/eqlKylkzLWqK0lvVeHboLLXrDTNnGQyWIaPM-lk4V0xdpY7v8TOMZ-fAjMiWo6wl0pKYG3q15F55Jmu00j9eOTZNKqgTDc3HOQv_Gf5W80qv0DSZdFxT6Jg8KAXke-H38_XKN2QxCHriRAR4dAlDWEKk8NpfwQEsaSAxa9644fc6x14w73IhetdYdnEVdfpt?purpose=fullsize &quot;width=100%&quot;)\" id=\"note-1775383915831-24\">Специфични видове.</span></strong></li></ul><h3><span class=\"editor-note\" data-note=\"![Image](https://images.openai.com/static-rsc-4/YvZnrkvUxQXUnnLb8P588ny03r4bjmoXPSN4WVzyam66-rUWCqQXQxBpLWpx-b6S8AKZbbBI72vbKKl86hnT2wtwLY1-0kEL6j3fdIrlHewwSmopIsY06FUzwZFpzzmkWMHouYPxoCGEk2UG0skvv7zoh8LLZLM3PZXWhm7QUSGtwKoJtHmSZ-JZtaFxtLyn?purpose=fullsize &quot;width=100%&quot;)\" id=\"note-1775384119196-0\">Медуларен карцином</span></h3><p>Въпреки че клетките му изглеждат силно атипични, този тумор има сравнително добра прогноза.</p><ul><li><strong>Макроскопия:</strong> Добре ограничена форма, мека консистенция, често с некрози и кръвоизливи.</li><li><strong>Микроскопия (Критерии на Foote &amp; Stewart):</strong></li><ol><li>Рязко отграничаване от околната тъкан.</li><li><strong>Синцитиален растеж</strong> (клетките изглеждат като прелети една в друга).</li><li>Силно атипични, големи везикуларни ядра.</li><li>Висок митотичен индекс.</li><li><strong>Масивна лимфоцитна инфилтрация</strong> в стромата (обхващаща над 75% от периферията).</li></ol></ul><h3><span class=\"editor-note\" data-note=\"![Image](https://images.openai.com/static-rsc-4/eP44lqdxIUnE_GGeysH-Ng5dC9hf-8oT8aDsDCiuQFKHri6n2rmxDvcej6g7L01joRwdoFRT8DPD_rkyyQgIkLFR0DR--IGIkfeAv3zAQ1jHGwkMW3ic1dy1i-MNxaSPrpc6VYQwzhJ6K66RIpgik_GwAZRXhz59PyRozIge6dvojiLmQR-B40Ot6vrTpBqo?purpose=fullsize &quot;width=100%&quot;)\" id=\"note-1775384156133-1\">Муцинозен (Колоиден) карцином</span></h3><ul><li><strong>Макроскопия:</strong> Добре ограничена, мека, със специфичен <strong>слузест/желатинозен вид</strong> на среза.</li><li><strong>Микроскопия:</strong> Характеризира се с „езера“ от екстрацелуларна слуз (муцин), в които плуват малки групи от туморни клетки.</li><li><strong>Прогноза:</strong> Много добра при „чистите“ форми (без дуктален компонент). Средната преживяемост е висока.</li></ul><h3><span class=\"editor-note\" data-note=\"![Image](https://images.openai.com/static-rsc-4/77MomKTpEicWeMA2eWLx-cIYdtgCTVUKzi2jtZoidUiL3d_VH4veu6qu_ZeijxMvsPZt20UrauQfbSThExXEd7qwAEewJnWAhFI6cPS4vZDrkrWd-HKR6NyVNV4141SNJjTraufk-CSMLe4vCY4SYdBafo99CoXClGHXxCHcrzRJ9Fs8S0lTztXDvxKk-CY8?purpose=fullsize &quot;width=80%&quot;)\" id=\"note-1775384185914-2\">Тубуларен карцином</span></h3><ul><li><strong>Микроскопия:</strong> Изграден от правилни тубули, тапицирани с <strong><u>един ред</u></strong> мономорфни клетки.</li><li><strong>Диференциална диагноза:</strong> Трябва да се различи от бенигнената <em>склерозираща аденоза</em>. При тубуларния карцином <strong>липсват базална мембрана и миоепителен слой</strong>.</li><li><strong>Прогноза:</strong> Отлична.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Стадиране и прогностични фактори</h2><h3>pTNM Класификация</h3><ul><li><strong>pTis</strong> - неинвазивен дуктален или лобуларен карцином</li><li><strong>рТ1</strong> - туморът е под 2 cm</li><li><strong>рТ2 </strong>- туморът е над 2 и под 5 cm&nbsp;</li><li><strong>рТЗ </strong>- туморът е над 5 cm&nbsp;</li><li><strong>рТ4 </strong>- тумор, ангажиращ гръдната стена или кожата</li><li><strong>pNO </strong>- без метастази в лимфните възли</li><li><strong>pN1 </strong>- метастази в несраснали, свободно подвижни хомолатерални лимфни възли</li><li><strong>pN2 </strong>- метастази в хомолатералните лимфни възли, които са сраснали в пакет или са прираснали към съседни структури</li><li><strong>pN3 </strong>- метастази в хомолатералните супраклавикуларни или инфраклавикуларни лимфни възли</li><li><strong>М </strong>- далечни метастази, включително и метастази в супраклавикуларните лимфни възли.</li></ul><h3>Основни прогностични фактори</h3><ol><li><strong>Степен на диференциация (G):</strong> По схемата на <em>Bloom &amp; Richardson</em> (според <p>брой митози, ядрен полиморфизъм и формиране на тубули</p>) се класифицифат като високо-, умерено-, и нискодиференцирани.</li><li><strong>Съдова инвазия:</strong> Рисков фактор за метастази и рецидиви.</li><li><strong>Хормонален статус:</strong> Естроген и прогестерон позитивните карциноми имат <strong>по-добра прогноза</strong>.</li><li><strong>Генетични маркери:</strong> Свръхекспресия на <strong>c-erb B-2</strong> (HER2/neu), мутации в <strong>p53</strong> и висок пролиферативен индекс са белези за <strong>лоша прогноза</strong>.</li></ol><br><span style=\"color: rgb(88, 129, 87); font-weight: 600\"><br></span>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.js\"></script>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/contrib/auto-render.min.js\"></script>\n<script>\nrenderMathInElement(document.body, {\n  delimiters: [\n    {left: '$$', right: '$$', display: true},\n    {left: '$', right: '$', display: false},\n    {left: '\\\\[', right: '\\\\]', display: true},\n    {left: '\\\\(', right: '\\\\)', display: false}\n  ],\n  throwOnError: false\n});\n</script>\n</body>\n</html>";
